INSERT INTO `city_content_edit` VALUES (1,55,5,1,1,'莫札特廣場','全天',NULL,1,NULL,0,NULL,NULL,NULL,NULL,NULL,'Mozartplatz，5020 Salzburg',NULL,NULL,NULL,NULL,'https://api.lumoguide.com/storage/uploads/FQLYQNnSq1k3xTq0hh4K.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/FQLYQNnSq1k3xTq0hh4K.png\"]',1,NULL,'2025-10-08 18:43:12','2025-10-08 18:44:23'),(2,37,5,1,1,'莫札特出生地','5月-10月 9:00-18:00 11月-4月10:00-17:00',NULL,0,NULL,0,'15歐元',NULL,NULL,NULL,'https://mozarteum.at/mozart-museen/','Getreidegasse 9, A-5020 Salzburg',NULL,NULL,NULL,'沃爾夫岡·阿馬德·莫扎特於1756年1月27日出生在這棟房子里，如今這裡已成為世界上參觀人數最多的博物館之一。\n\n在沃爾夫岡·阿馬德·莫扎特的出生地，人們能夠最真切地感受到他的個人魅力和音樂魅力，這是其他任何地方都無法比擬的。','https://api.lumoguide.com/storage/uploads/20251109/coO1Wlkgzv8AWaL54xIC.jpg','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/coO1Wlkgzv8AWaL54xIC.jpg\"]',1,NULL,'2025-11-19 10:20:01','2025-11-19 10:22:11'),(3,56,23,7,7,'2025 Ruperti Kirtag教堂節日','2025-09-19','2025-09-24',0,NULL,0,NULL,NULL,NULL,NULL,NULL,'Salzburg',NULL,NULL,NULL,'每年紀念聖Rupert誕辰的教堂紀念活動，有小型遊樂場，小吃和手工集市','https://api.lumoguide.com/storage/uploads/20251109/7BSrM7BuzViqHNsvQ5VR.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/7BSrM7BuzViqHNsvQ5VR.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/L8hWAAD0edqZLLfsK7tj.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/CzeWPJz1NulJf0aF0H6b.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/fueyFjB5SgZepNMeIJbF.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/ZF2lXgwVTtI7N8PCA70s.png\"]',1,NULL,'2025-11-21 07:11:47','2025-11-21 07:37:31'),(4,59,23,7,7,'2025/26聖誕市集','2025-11-20','2026-01-01',0,NULL,0,NULL,NULL,NULL,NULL,'https://christkindlmarkt.co.at','Altstadt Salzburg',NULL,NULL,NULL,'薩爾茨堡的聖誕市場\n\n當 11 月底降臨薩爾茨堡時，一個特別美好的季節就開始了。現在是一個絕佳的機會，既可以遊覽城市，又可以逛逛聖誕市場。裝飾得喜氣洋洋的城市比平時更閃亮，熱栗子、辛辣的熱紅酒和美味餅乾的氣味飄蕩在老城區的小巷里。\n在降臨節期間逛逛薩爾茨堡，是一種真正的體驗。不要錯過大教堂廣場和王宮廣場上的薩爾茨堡聖誕市場。這個歷史悠久的聖誕市場是世界上最美麗的降臨節市場之一。令人著迷的赫爾布倫降臨節魔術特別受家庭歡迎。距離米拉貝爾花園不遠的米拉貝爾廣場上的寧靜的降臨節集市也值得一去，霍恩薩爾茨堡要塞上的要塞降臨節集市也是如此。','https://api.lumoguide.com/storage/uploads/20251121/DMHw8f6BmJCKF8rbupcz.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/DMHw8f6BmJCKF8rbupcz.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/Olr2Pm9QqcIktYQdVtcg.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/NqM7mXpmVboRueQWYzAs.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/yhFkuKkbtTMsYaNxN7tv.png\"]',1,NULL,'2025-11-21 07:37:45','2025-12-08 22:46:28'),(5,33,23,6,6,'Billa 超市',NULL,NULL,0,NULL,0,NULL,NULL,NULL,NULL,NULL,'Griesgasse 19/21, 5020 Salzburg',NULL,NULL,NULL,'舊城區最大的超市','https://api.lumoguide.com/storage/uploads/20251109/S0TTLMVcXW413yILzKfo.jpg','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/S0TTLMVcXW413yILzKfo.jpg\"]',1,NULL,'2025-12-04 21:54:58','2025-12-10 04:44:01'),(6,59,23,7,7,'2025/26聖誕市集','2025-11-20','2026-01-01',0,NULL,0,NULL,NULL,NULL,NULL,'https://christkindlmarkt.co.at','Altstadt Salzburg',NULL,NULL,NULL,'薩爾茨堡的聖誕市場\r\n\r\n當 11 月底降臨薩爾茨堡時，一個特別美好的季節就開始了。現在是一個絕佳的機會，既可以遊覽城市，又可以逛逛聖誕市場。裝飾得喜氣洋洋的城市比平時更閃亮，熱栗子、辛辣的熱紅酒和美味餅乾的氣味飄蕩在老城區的小巷里。\r\n在降臨節期間逛逛薩爾茨堡，是一種真正的體驗。不要錯過大教堂廣場和王宮廣場上的薩爾茨堡聖誕市場。這個歷史悠久的聖誕市場是世界上最美麗的降臨節市場之一。令人著迷的赫爾布倫降臨節魔術特別受家庭歡迎。距離米拉貝爾花園不遠的米拉貝爾廣場上的寧靜的降臨節集市也值得一去，霍恩薩爾茨堡要塞上的要塞降臨節集市也是如此。','https://api.lumoguide.com/storage/uploads/20251121/DMHw8f6BmJCKF8rbupcz.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/DMHw8f6BmJCKF8rbupcz.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/Olr2Pm9QqcIktYQdVtcg.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/NqM7mXpmVboRueQWYzAs.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251121\\/yhFkuKkbtTMsYaNxN7tv.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251209\\/8hdJfU7SgIyeMNUPx3ua.png\",\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251209\\/w6qDng6wDBESZOuNkoKH.png\"]',1,NULL,'2025-12-0