INSERT INTO `city_edit` VALUES (1,22,9,6,'东京','Tokyo',1,5,21,NULL,NULL,NULL,0,'日元','日语','1E','h','dkjaf jkadfhkjfhkf pig oil Igbo h','Jaheim ji k joshes kj in k.dddddd','https://api.lumoguide.com/storage/uploads/20251113/XhdFRWdvijTJJIg7fIZ1.png','[\"https://api.lumoguide.com/storage/uploads/20251113/XhdFRWdvijTJJIg7fIZ1.png\", \"https://api.lumoguide.com/storage/uploads/20251210/WC4cKrj3oHX7zvm5A92G.png\"]',2,'22222',0,0,0,0,0,0,1,'2026-01-20 01:07:38','2026-01-20 01:07:55'),(2,22,9,6,'东京','Tokyo',1,5,21,NULL,NULL,NULL,0,'日元','日语','1E','hu','dkjaf jkadfhkjfhkf pig oil Igbo h ga','Jaheim ji k joshes kj in k.dddddddd','https://api.lumoguide.com/storage/uploads/20251113/XhdFRWdvijTJJIg7fIZ1.png','[\"https://api.lumoguide.com/storage/uploads/20251113/XhdFRWdvijTJJIg7fIZ1.png\", \"https://api.lumoguide.com/storage/uploads/20251210/WC4cKrj3oHX7zvm5A92G.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-01-20 01:08:06','2026-01-20 01:08:24'),(3,33,3,3,'台北','Taipei',1,5,69,NULL,'121.55723823488972','25.029344604936995',0,'新台幣','國語','245萬','華人','臺北市，通稱臺北，是中華民國的直轄市，位於臺灣北部，地處臺北盆地東北半部，外圍由新北市環繞。全市轄有12區，其中市政府所在地為信義區。全市設籍人口約245萬人，人口密度每平方公里近9,000人，是中華民國人口第四多、人口密度最高的建制市。以臺北市中心為發展核心的臺北都會區，為臺灣的首都圈及第一大都會區。\r\n\r\n臺北城市建立的歷史，最早可追溯自清代後期1876年成立的臺北府、以及1884年竣工的臺北城；臺北則在1885年臺灣建省後成為臺灣首府，持續至今。日治時代中期1920年成立的臺北州轄市，乃臺北正式建市之始[9]。1945年進入中華民國時代之初為臺灣省省轄市及省會（後者至1956年省府南遷中興新村為止），1949年隨著政府遷臺成為首都，1967年升格為直轄市，發展至今已成為臺灣金融、經濟、政治、科技、教育、文化等領域的發展中心，並與周邊縣市形成大型都會區。臺北在2020年被全球化及世界城市研究網絡（GaWC）評為「Alpha−」級城市。','17世紀初—1684年\r\n\r\n荷蘭人1654年繪製的《大臺北古地圖》。\r\n根據荷蘭人1654年繪製的《大臺北古地圖》記載，臺北最早為平埔族原住民凱達格蘭人生活之地，部分平埔族有初步的開墾和灌溉，其番社址位置與後世並無太多變動。艋舺（今萬華）為凱達格蘭語獨木舟的音譯，因其西側為新店溪的港口，先民開發時有很多獨木舟停靠；當時地圖是以荷蘭文「Handelsplaasts」標示，即交易場所的意思，足見其商業傳統之古老；大龍峒（今大同區北部）被標為「Pourompon」聚落。早在漢人之前，荷蘭人就曾經在劍潭墾荒，松山地區於泉州人來之前，在明鄭前後就有福州人前來開墾。換言之，臺北從17世紀初開始，就已因西班牙、荷蘭、漢人的多元統治，而具有都市的粗胚樣貌。\r\n\r\n1684年—1895年\r\n\r\n欽差行臺，攝於約1901年。\r\n臺北在1684年（清康熙23年）劃屬大清帝國臺灣府諸羅縣，首度納入滿人行政體系。1709年，泉州人陳天章、陳逢春、賴永和、陳憲伯、戴天樞合股立陳賴章墾號，向諸羅縣申請開墾大佳臘（之後多寫作「大加蚋堡」）地方。1723年，巡臺御史吳達禮報請朝廷增設淡水廳，並管轄大甲溪以北，但當時的臺灣仍以臺南作為政治、經濟中心。\r\n\r\n19世紀中葉，淡水河流域的物產貿易（特別是茶葉）興起，艋舺及大稻埕（今大同區西南部）先後成爲重要貿易據點，臺灣經濟重心逐漸北移，清代官方決定在艋舺與大稻埕間的田野地，興建臺北城作為行政中心，城垣於1884年底正式落成。劉銘傳在西仔反戰役棄守基隆後，率千餘名士兵，攜大量財寶、糧秣欲離開臺北城，行經艋舺時，商民認為劉銘傳想落跑，遂將其監禁在艋舺龍山寺內，直至承諾會坐鎮臺北督戰後才獲釋放。\r\n\r\n1885年臺灣建省，劉銘傳擔任臺灣省首任巡撫，開始建設大稻埕至基隆與新竹的鐵路，加強郵電、道路等基礎建設，並將臺灣巡撫衙門及布政使司衙門設置於城內（現址為中山堂），臺北的都市雛形至此已初步建立。1894年，繼任巡撫邵友濂正式將省會由橋孜圖（今臺中市南區）移至臺北，奠定臺北至今為臺灣政治和經濟中心的地位。\r\n\r\n1895年—1945年\r\n\r\n臺灣總督府（下方冒煙者）於臺北大空襲遭轟炸。\r\n1895年，大清帝國於甲午戰爭戰敗，將臺灣割讓給日本，臺北仍作為日本統理臺灣的政治中心；並立縣廳制設臺北縣。日治初期以原有的兩座衙門作爲臺灣總督府，直到1919年總督府新廳舍（今總統府）落成爲止。1900年起，日本政府拆除臺北城牆及西門，在原址闢築四條三線道路，興建自來水及下水道系統，以原臺北城內的區域（日人稱爲「城內」）作為中樞政府廳舍集中地，以及在臺日本人的商業地帶，並分階段進行市街改正計劃，街道和建築風貌略爲西化，另外也興建公園及其它公共建築，臺北逐漸具有現代都市的型態。自此，臺北城慢慢由中國傳統模式，變成中西混合的現代化城市佈局與運作模式，尤其日治中央政府所在的官廳集中區之現代化建設，對今日臺北城面貌影響最深。1897年日本政府為在臺北城進行地下水道修建工程，利用現代測量儀器繪製《臺北及大稻埕、艋舺略圖》，精準紀錄臺北城廓與街道樣貌，相較於之前不精確的中式地圖，更能滿足殖民政府軍事、政治管理與經營上的需求。1897同年開始到1901年，日本政府拆除部分城垣，以利於鐵路交通建設，可說是臺北城現代化的開端，臺北城也從防禦型的中式城池變成開放城市。\r\n\r\n1920年10月1日市制實施，成為臺北州轄臺北市，與同時成立的臺南及臺中為臺灣最早的三個市。二戰期間，美軍空襲臺北，造成破壞及市民傷亡，日本戰敗後，中華民國國民政府代表同盟國在臺北公會堂（今中山堂）舉行受降儀式，日治時期劃下句點。','https://api.lumoguide.com/storage/uploads/20251218/Y0aiE1Wga15jARVxaows.png','[\"https://api.lumoguide.com/storage/uploads/20251218/Y0aiE1Wga15jARVxaows.png\", \"https://api.lumoguide.com/storage/uploads/20251218/uKzzQnXqkWryOX7wW7Oo.png\", \"https://api.lumoguide.com/storage/uploads/20260120/mSfbNHdXgoT2prkFLcBk.png\", \"https://api.lumoguide.com/storage/uploads/20260120/PVexpvlUJUJT7QMgbQry.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-01-20 07:24:03','2026-01-20 07:25:22'),(4,37,15,8,'米斯巴赫','Miesbach',2,29,27,NULL,NULL,NULL,0,'欧元','德语','1.1万','德意志民族','米斯巴赫（Miesbach）位于德国巴伐利亚州上巴伐利亚地区，距离慕尼黑以南约 45 公里，坐落在阿尔卑斯山北麓，毗邻著名的泰根湖（Tegernsee）和施利尔湖（Schliersee）。这里山峦起伏、空气清新，是远离城市喧嚣、亲近自然的理想之地。小城保留着浓郁的巴伐利亚传统风情：色彩斑斓的壁画建筑、安静温馨的老城街道，以及充满地方特色的节庆活动。得天独厚的自然环境让米斯巴赫成为四季皆宜的旅游目的地。春夏适合徒步、骑行和湖畔休闲；秋季层林尽染，风景如画；冬季则可前往周边山区体验滑雪等冬季运动。','米斯巴赫拥有悠久的历史，早在 11 世纪，这里就因地处重要的贸易通道而逐渐发展成为区域性的聚居点。在中世纪和近代早期，米斯巴赫以农业、手工业和贸易为主要经济支柱，并逐渐发展出浓厚的巴伐利亚地方文化。17 至 18 世纪，随着天主教文化的兴盛，城中修建了多座教堂和宗教建筑，为城市留下了丰富的历史遗产。19 世纪是米斯巴赫发展史上的重要阶段。这里成为德国最早的石油开采地之一，在德国工业史上占有一席之地。随后，铁路的开通进一步促进了城市与慕尼黑及阿尔卑斯地区的联系，使米斯巴赫逐渐发展为一个宜居的小城。','https://api.lumoguide.com/storage/uploads/20260128/PPny17wGvyTMbufaVwVu.png','[\"https://api.lumoguide.com/storage/uploads/20260128/PPny17wGvyTMbufaVwVu.png\", \"https://api.lumoguide.com/storage/uploads/20260128/x3mPBFh7l1CzmkGGik3J.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-01-28 13:14:18','2026-01-28 13:14:28'),(5,37,15,8,'米斯巴赫','Miesbach',2,29,27,NULL,NULL,NULL,0,'欧元','德语','1.1万','德意志民族','米斯巴赫（Miesbach）位于德国巴伐利亚州上巴伐利亚地区，距离慕尼黑以南约 45 公里，坐落在阿尔卑斯山北麓，毗邻著名的泰根湖（Tegernsee）和施利尔湖（Schliersee）。这里山峦起伏、空气清新，是远离城市喧嚣、亲近自然的理想之地。小城保留着浓郁的巴伐利亚传统风情：色彩斑斓的壁画建筑、安静温馨的老城街道，以及充满地方特色的节庆活动。得天独厚的自然环境让米斯巴赫成为四季皆宜的旅游目的地。春夏适合徒步、骑行和湖畔休闲；秋季层林尽染，风景如画；冬季则可前往周边山区体验滑雪等冬季运动。','米斯巴赫拥有悠久的历史，早在 11 世纪，这里就因地处重要的贸易通道而逐渐发展成为区域性的聚居点。在中世纪和近代早期，米斯巴赫以农业、手工业和贸易为主要经济支柱，并逐渐发展出浓厚的巴伐利亚地方文化。17 至 18 世纪，随着天主教文化的兴盛，城中修建了多座教堂和宗教建筑，为城市留下了丰富的历史遗产。19 世纪是米斯巴赫发展史上的重要阶段。这里成为德国最早的石油开采地之一，在德国工业史上占有一席之地。随后，铁路的开通进一步促进了城市与慕尼黑及阿尔卑斯地区的联系，使米斯巴赫逐渐发展为一个宜居的小城。','https://api.lumoguide.com/storage/uploads/20260128/PPny17wGvyTMbufaVwVu.png','[\"https://api.lumoguide.com/storage/uploads/20260128/PPny17wGvyTMbufaVwVu.png\", \"https://api.lumoguide.com/storage/uploads/20260128/sagWNIOMO0YtC4gBoX4p.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-01-28 13:15:12','2026-01-28 13:20:17'),(6,33,3,3,'台北','Taipei',1,5,69,NULL,'121.55723823488972','25.029344604936995',0,'新台幣','國語','245萬','華人','臺北市，通稱臺北，是中華民國的直轄市，位於臺灣北部，地處臺北盆地東北半部，外圍由新北市環繞。全市轄有12區，其中市政府所在地為信義區。全市設籍人口約245萬人，人口密度每平方公里近9,000人，是中華民國人口第四多、人口密度最高的建制市。以臺北市中心為發展核心的臺北都會區，為臺灣的首都圈及第一大都會區。\r\n\r\n臺北城市建立的歷史，最早可追溯自清代後期1876年成立的臺北府、以及1884年竣工的臺北城；臺北則在1885年臺灣建省後成為臺灣首府，持續至今。日治時代中期1920年成立的臺北州轄市，乃臺北正式建市之始[9]。1945年進入中華民國時代之初為臺灣省省轄市及省會（後者至1956年省府南遷中興新村為止），1949年隨著政府遷臺成為首都，1967年升格為直轄市，發展至今已成為臺灣金融、經濟、政治、科技、教育、文化等領域的發展中心，並與周邊縣市形成大型都會區。臺北在2020年被全球化及世界城市研究網絡（GaWC）評為「Alpha−」級城市。','17世紀初—1684年\r\n\r\n荷蘭人1654年繪製的《大臺北古地圖》。\r\n根據荷蘭人1654年繪製的《大臺北古地圖》記載，臺北最早為平埔族原住民凱達格蘭人生活之地，部分平埔族有初步的開墾和灌溉，其番社址位置與後世並無太多變動。艋舺（今萬華）為凱達格蘭語獨木舟的音譯，因其西側為新店溪的港口，先民開發時有很多獨木舟停靠；當時地圖是以荷蘭文「Handelsplaasts」標示，即交易場所的意思，足見其商業傳統之古老；大龍峒（今大同區北部）被標為「Pourompon」聚落。早在漢人之前，荷蘭人就曾經在劍潭墾荒，松山地區於泉州人來之前，在明鄭前後就有福州人前來開墾。換言之，臺北從17世紀初開始，就已因西班牙、荷蘭、漢人的多元統治，而具有都市的粗胚樣貌。\r\n\r\n1684年—1895年\r\n\r\n欽差行臺，攝於約1901年。\r\n臺北在1684年（清康熙23年）劃屬大清帝國臺灣府諸羅縣，首度納入滿人行政體系。1709年，泉州人陳天章、陳逢春、賴永和、陳憲伯、戴天樞合股立陳賴章墾號，向諸羅縣申請開墾大佳臘（之後多寫作「大加蚋堡」）地方。1723年，巡臺御史吳達禮報請朝廷增設淡水廳，並管轄大甲溪以北，但當時的臺灣仍以臺南作為政治、經濟中心。\r\n\r\n19世紀中葉，淡水河流域的物產貿易（特別是茶葉）興起，艋舺及大稻埕（今大同區西南部）先後成爲重要貿易據點，臺灣經濟重心逐漸北移，清代官方決定在艋舺與大稻埕間的田野地，興建臺北城作為行政中心，城垣於1884年底正式落成。劉銘傳在西仔反戰役棄守基隆後，率千餘名士兵，攜大量財寶、糧秣欲離開臺北城，行經艋舺時，商民認為劉銘傳想落跑，遂將其監禁在艋舺龍山寺內，直至承諾會坐鎮臺北督戰後才獲釋放。\r\n\r\n1885年臺灣建省，劉銘傳擔任臺灣省首任巡撫，開始建設大稻埕至基隆與新竹的鐵路，加強郵電、道路等基礎建設，並將臺灣巡撫衙門及布政使司衙門設置於城內（現址為中山堂），臺北的都市雛形至此已初步建立。1894年，繼任巡撫邵友濂正式將省會由橋孜圖（今臺中市南區）移至臺北，奠定臺北至今為臺灣政治和經濟中心的地位。\r\n\r\n1895年—1945年\r\n\r\n臺灣總督府（下方冒煙者）於臺北大空襲遭轟炸。\r\n1895年，大清帝國於甲午戰爭戰敗，將臺灣割讓給日本，臺北仍作為日本統理臺灣的政治中心；並立縣廳制設臺北縣。日治初期以原有的兩座衙門作爲臺灣總督府，直到1919年總督府新廳舍（今總統府）落成爲止。1900年起，日本政府拆除臺北城牆及西門，在原址闢築四條三線道路，興建自來水及下水道系統，以原臺北城內的區域（日人稱爲「城內」）作為中樞政府廳舍集中地，以及在臺日本人的商業地帶，並分階段進行市街改正計劃，街道和建築風貌略爲西化，另外也興建公園及其它公共建築，臺北逐漸具有現代都市的型態。自此，臺北城慢慢由中國傳統模式，變成中西混合的現代化城市佈局與運作模式，尤其日治中央政府所在的官廳集中區之現代化建設，對今日臺北城面貌影響最深。1897年日本政府為在臺北城進行地下水道修建工程，利用現代測量儀器繪製《臺北及大稻埕、艋舺略圖》，精準紀錄臺北城廓與街道樣貌，相較於之前不精確的中式地圖，更能滿足殖民政府軍事、政治管理與經營上的需求。1897同年開始到1901年，日本政府拆除部分城垣，以利於鐵路交通建設，可說是臺北城現代化的開端，臺北城也從防禦型的中式城池變成開放城市。\r\n\r\n1920年10月1日市制實施，成為臺北州轄臺北市，與同時成立的臺南及臺中為臺灣最早的三個市。二戰期間，美軍空襲臺北，造成破壞及市民傷亡，日本戰敗後，中華民國國民政府代表同盟國在臺北公會堂（今中山堂）舉行受降儀式，日治時期劃下句點。','https://api.lumoguide.com/storage/uploads/20260120/PVexpvlUJUJT7QMgbQry.png','[\"https://api.lumoguide.com/storage/uploads/20260120/PVexpvlUJUJT7QMgbQry.png\", \"https://api.lumoguide.com/storage/uploads/20251218/uKzzQnXqkWryOX7wW7Oo.png\", \"https://api.lumoguide.com/storage/uploads/20260120/mSfbNHdXgoT2prkFLcBk.png\", \"https://api.lumoguide.com/storage/uploads/20251218/Y0aiE1Wga15jARVxaows.png\", \"https://api.lumoguide.com/storage/uploads/20260129/kjYpeDad4G5nhFMCsZL5.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-01-29 02:23:28','2026-02-05 22:22:05'),(7,38,3,3,'聖基爾根','St.Gilgen',2,29,20,NULL,NULL,NULL,0,'歐元','德語','約4千','日耳曼人','聖吉爾根（St. Gilgen）是奧地利薩爾斯堡郊區（弗拉赫高地區 Flachgau）的一個市鎮，位於薩爾斯堡薩爾茨卡默古特湖區。該市鎮隸屬於塞基興法院管轄區（Seekirchen am Wallersee），擁有 4,042 名居民（截至 2025 年 1 月 1 日），並以避暑勝地而聞名遐邇。','地名由來\n聖吉爾根是以聖艾吉迪烏斯（Saint Aegidius）命名的，在德語區他也常被稱為 Gilg 或 Gilgian。該地最初名為「Oberdrum」，這個名字暗示了其地理位置，即位於湖泊的上端（Drum 或 Trum意為末端/部分）。直到 19 世紀，人們仍稱此地為「聖艾吉迪（Sankt Ägidi）」。\n史前與羅馬時期\n此地區早在史前時代就有人居住。沙夫林（Scharfling）的樁屋遺址可追溯至西元前 5000 年；而蒙德塞（Mondsee）湖畔的遺址更是新石器時代晚期（西元前 3800-3300 年）阿爾卑斯地區最重要的定居點之一，並被命名為「蒙德塞文化」。此外，在 Oberburgau 發現了青銅時代的遺跡，鐵器時代的凱爾特時期則受到鄰近哈修塔特（Hallstatt）文化的影響。羅馬時期，從伊希爾谷（Ischltal）向東延伸的古道是一條重要的羅馬大道，連接薩爾斯堡（Iuvavum）與巴德伊希爾（Ischl），儘管其沿著沃夫岡湖的具體路線尚不明確，但這些影響顯示當時湖岸與山區已有點狀定居點。\n中世紀與領土爭議\n約西元 750 年，巴伐利亞公爵奧迪洛（Odilo）將阿伯湖（Abersee，即沃夫岡湖舊稱）地區贈予薩爾斯堡教會進行開發。到了 13 世紀，沃夫岡河谷基本開發完成，當時約有十間房屋及首座教堂。中世紀時，前往聖沃夫岡的朝聖活動是歐洲最重要的朝聖路徑之一，導致該地區在薩爾斯堡教區、蒙德塞修道院以及後來的哈布斯堡奧地利之間存在領土爭議。此外，鄰近的伊希爾鹽山也影響了當地的政治地位。\n近代邊境協議\n13 世紀起，聖吉爾根與史特羅布爾（Strobl）、富緒（Fuschl）共同組成「許騰斯坦領地（Herrschaft Hüttenstein）」。1689 年 5 月 26 日，神聖羅馬帝國皇帝利奧波德一世與親王大主教通恩（Thun）簽署國家條約，才正式確定了薩爾斯堡與奧地利之間的邊界。\n旅遊業的興起與發展\n聖吉爾根一直是沃夫岡湖朝聖之路的重要據點，信徒可選擇搭船或經由法爾肯施坦（Falkenstein）的陸路。隨著人口增加，教堂曾兩度重建。19 世紀，原本被懸崖阻斷的道路被修建成真正的車道。1873 年沃夫岡湖航運開啟，特別是 1893 年「薩爾斯堡鹽湖區窄軌鐵路（SKGLB）」建成後，這個原本平凡的小村莊迅速崛起成為著名的避暑勝地。名醫西奧多·比爾羅特（Theodor Billroth）等知名人士紛紛在此興建夏季別墅。兩戰期間，這裡還形成了「秦肯巴赫畫家村」藝術社群。\n黑暗時期與近期事件\n1938 年至 1942 年底，此地曾設有達豪集中營的分營，囚犯被強迫為納粹高層建造別墅。\n最近的一次重大自然災害發生在 2023 年耶穌受難日，Zwölferhorn 山下方發生山崩，8 公頃的土堆在 12 小時內向山下移動了約 20 公尺。','https://api.lumoguide.com/storage/uploads/20260224/3l02YY2WjBBVb4OdINsm.png','[\"https://api.lumoguide.com/storage/uploads/20260224/3l02YY2WjBBVb4OdINsm.png\", \"https://api.lumoguide.com/storage/uploads/20260225/RXPpJrhKT0cqPFIN99xI.png\", \"https://api.lumoguide.com/storage/uploads/20260225/hz3580rl40vtvnyG0F3p.png\", \"https://api.lumoguide.com/storage/uploads/20260225/Fmtc3W47TDkfdoG6iGxa.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-02-25 04:32:31','2026-02-25 19:41:55'),(8,43,3,3,'廈門','Xiamen',1,5,69,NULL,NULL,NULL,0,'人民幣','廈門話（閩南語）','100萬','漢族為主','廈門市，別稱鷺島，簡稱廈或鷺，是位於中華人民共和國福建省東南部的城市，是中國東南沿海重要的中心城市、最早對外開放的四個經濟特區之一，亦屬計劃單列市及副省級城市。廈門市和泉州市、漳州市接壤，與金門縣隔海對望，是由廈門島、鼓浪嶼等島與海滄、集美、同安、翔安等沿海地區組成的海灣型城市。全市下轄思明、湖裡、集美、海滄、同安、翔安六個行政區，是國務院批復的現代海洋城市、國際性綜合交通樞紐城市。\r\n廈門市是中國著名的僑鄉、亞洲重要的交通樞紐：廈門港為中國第7大、世界第13大集裝箱港口，廈門高崎國際機場是中國第8大出入境空港，第4大國際及地區中轉空港。此外，廈門是著名的風景旅遊城市，有「城在海上，海在城中」的美譽，著名景點有鼓浪嶼（2017年被列為世界文化遺產）、萬石山、集美學村、南普陀寺、廈門大學等。2024年廈門市被GaWc評為Beta級的世界城市。','一、 古代與命名（晉代－明代）\r\r\n同安立縣： 西晉（282年）始設同安縣，轄今廈門與金門。\r\r\n早期名稱： 唐代稱「新城」，後因產稻碩穗改稱「嘉禾嶼」。\r\r\n廈門由來： 明洪武二十年（1387年）設防倭要塞，雅稱「廈門」，意為大廈之門。\r\n\r\n二、 近代爭奪與通商（明末清初－民國）\r\r\n明鄭時期： 鄭成功改設「思明州」，以此為基地征服台灣。清軍與明鄭多次拉鋸奪島。\r\r\n通商口岸： 1689年開啟對英茶葉直出口；1842年《南京條約》後正式開港通商。\r\r\n租界與分治： 英、日等國在鼓浪嶼及廈門島設立租界。\r\r\n行政演變： 1935年正式設廈門市。抗戰期間曾遭日軍佔領，更名「廈門特別市」。\r\n\r\n三、 行政調整與擴張（1949年－1970年代）\r\r\n政權更迭： 1949年10月解放軍攻克廈門，成立市人民政府。\r\n\r\n轄區變更： 1950年代起，陸續將集美、灌口、同安、海滄等周邊區域由同安縣或龍溪縣劃歸廈門市管轄，形成今日地圖雛形。\r\n\r\n四、 改革開放與現代化（1980年至今）\r\r\n特區成立： 1980年設立全國首批經濟特區，1984年範圍擴大至全島。\r\r\n地位升格： 1988年批准為計劃單列市，1994年定為副省級市，並獲得特區立法權。\r\r\n區域調整： 2003年完成重大行政重組，撤併鼓浪嶼與開元區入思明區，析設翔安區，並將經濟特區擴展至全市。','https://api.lumoguide.com/storage/uploads/20260227/DNHzNaEFUTa52dSNuNij.png','[\"https://api.lumoguide.com/storage/uploads/20260227/DNHzNaEFUTa52dSNuNij.png\", \"https://api.lumoguide.com/storage/uploads/20260227/dfm6UMRH8CA7ISD8uaSu.png\", \"https://api.lumoguide.com/storage/uploads/20260227/MDW93JeShhmGtoXgDVfb.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-02-27 07:23:41','2026-02-27 20:54:07'),(9,47,3,3,'曼谷','Bangkok',1,6,75,NULL,NULL,NULL,1,'泰銖','泰語','約1000萬','泰族','曼谷 (Bangkok)\r\n地位與名稱： 泰國首都與最大城市，官方全名為「恭貼瑪哈納空」（Krung Thep Maha Nakhon）。它是泰國政治、經濟、文化及科技中心，都會區人口超過 1,400 萬。\r\n\r\n地理位置： 位於昭披耶河東岸，鄰近泰國灣。\r\n\r\n歷史發展： * 起源於 15 世紀的小型貿易集鎮。\r\n18 世紀後先後成為吞武里王朝與拉達那哥欣王朝的都城。\r\n19 世紀後期啟動近代化，20 世紀成為泰國歷次政治變革與示威的中心。\r\n\r\n現代影響力： * 國際地位： GaWC 評定為 Alpha− 級國際都市。\r\n經濟樞紐： 跨國公司地區總部集結，是東南亞金融、商業、醫療保健及交通樞紐。\r\n旅遊魅力： 以豐富的街頭生活、文化地標與紅燈區聞名，長期位居全球訪問量最高的旅遊目的地之列。','1. 起源 (Ursprung)\r\n\r\n早期定居： 曼谷最初僅是昭披耶河東岸的一個小漁村。1511 年，它首次出現在葡萄牙人的地圖上。\r\n\r\n貿易轉型： 約在 1680 年左右，該村南方僅有三個居住點：海關、荷蘭人於 1622 年建立的「阿姆斯特丹堡」（Fort Amsterdam）商館，以及名為 Ban Vat 的聚落。在阿瑜陀耶王國時期，這裡逐漸發展成為重要的貿易港口，是前往首都水路上的關鍵停靠站。\r\n\r\n遷都與擴建： 現代曼谷的雛形始於西岸的吞武里（Thonburi）。1767 年阿瑜陀耶遭緬甸摧毀後，鄭昭王（Taksin）於 1772 年定都吞武里。十年後（1782 年），現今扎克里王朝的開創者拉瑪一世將政權遷至東岸，並模仿舊都形制，在當時主要由華人居住的「Bang Kok」村落基礎上，開始建設名為拉達那哥欣（Rattanakosin）的首都。\r\n\r\n地名由來： 當時城市官方簡稱為「恭貼」（Krung Thep，意為天使之城），但西方商人與旅行者仍習慣沿用原有的村名「Bangkok」，這也成為今日國際通用的稱呼。\r\n\r\n2. 運河之城 (Die Stadt der Kanäle)\r\n\r\n東方威尼斯： 拉達那哥欣透過開鑿「洛運河」（Khlong Lot）成為昭披耶河河道轉彎處的人造島嶼。島中心建設了皇宮與供奉泰國國寶翡翠佛的玉佛寺（Wat Phra Kaeo）。\r\n\r\n水上生活： 當時整座城市佈滿了細密的運河網（Khlongs），交通、貿易甚至市場（水上市場）皆在水面進行，極少有陸路，因此曼谷曾被譽為「東方威尼斯」。\r\n\r\n現代化轉變： 自 19 世紀中葉起，為了應對日益增長的交通與城市擴張，運河陸續被填平改建為道路。1863 年，第一條鋪設石塊的馬路「石龍軍路」（Charoen Krung，西人稱為 New Road）正式落成。在拉瑪五世（朱拉隆功大帝）統治期間，曼谷修築了連接北部的鐵路、市內路面電車以及大量受歐洲風格影響的政府建築。\r\n\r\n3. 現代曼谷 (Das moderne Bangkok)\r\n\r\n擴張與戰爭： 20 世紀初，城市向北與向東擴張。1932 年首座跨河大橋「紀念大橋」（Memorial Bridge）通車，極大促進了西岸的發展。二戰期間，曼谷曾遭日軍佔領，並於 1944 年起受到盟軍轟炸，但賽後迅速復原並持續增長。\r\n\r\n都市爆炸： 20 世紀中葉，多數運河已被林蔭大道與公路取代（如著名的蘇坤畏路 Sukhumvit）。1960 至 1980 年代，建築業與高速公路開發達到前所未有的規模。\r\n\r\n政治與經濟動盪： 1970 年代，曼谷見證了重大的政治事件，包括 1973 年反對軍政府的群眾起義，以及 1976 年法政大學校園慘案。\r\n\r\n摩天大樓時代： 隨著 1980 年代的經濟騰飛（亞洲四小虎時期），曼谷大量興建高樓大廈，徹底改變了天際線，人口也隨之飆升，使其躍升為世界級大都會。1992 年 5 月（黑色五月），曼谷再次爆發反政府大規模抗爭。','https://api.lumoguide.com/storage/uploads/20260228/D5DkZyZq8bmilgTu8vRd.png','[\"https://api.lumoguide.com/storage/uploads/20260228/D5DkZyZq8bmilgTu8vRd.png\", \"https://api.lumoguide.com/storage/uploads/20260228/IPQds0P3bVVpKZfQ7gxb.png\", \"https://api.lumoguide.com/storage/uploads/20260228/50aqYu7iD2eJhcSDTADe.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-02-28 02:32:27','2026-02-28 02:32:36'),(10,48,3,3,'新加坡','Singapore',1,6,73,NULL,NULL,NULL,1,'新幣','英語','約604萬','華裔/馬來裔/印度裔','新加坡共和國 (Singapore)\r\n地理定位：位於東南亞中南半島南端，扼守麻六甲海峽咽喉。由 63 個島嶼組成，以「花園城市」與「小紅點」著稱。\r\n\r\n歷史沿革：\r\n殖民時期：1819 年由萊佛士建立貿易站，成為英國重要戰略據點。\r\n二戰與自治：歷經日據時期（1942-1945），1959 年成立自治邦。\r\n獨立建國：1963 年加入馬來西亞，隨後於 1965 年 8 月 9 日被逐出聯邦，正式獨立。\r\n\r\n經濟地位：\r\n「亞洲四小龍」之一，現為全球重要金融、貿易及物流中心。\r\n人均 GDP 與人類發展指數位居全球前列。\r\n\r\n社會現況：屬高密度居住國家；以多元種族、文化與公民民族主義為立國基礎，住房自有率極高。','新加坡的名稱與歷史發展\r\n\r\n一、 名稱由來：獅城 (Singapur)\r\n語源：源於梵語，由 Singha（सिंह，意為「獅子」）與 Pura（पुर，意為「城市」）組成，故稱「獅城」。\r\n傳說：1299 年，來自三佛齊王國（Srivijaya）首都巨港的王子桑尼拉·朱他馬（Sang Nila Utama）抵達此地。據說他在叢林中看見了一隻獅子（儘管該地區並無獅子，推測可能是馬來亞虎），他認為這是吉兆，遂命名為「獅城」並建立聚落。\r\n魚尾獅 (Merlion)：自 1964 年起成為新加坡的標誌，結合了獅頭與魚身的傳說形象。\r\n\r\n二、 早期貿易與殖民起點\r\n古稱與衰落：最早見於 3 世紀的中國文獻。原名為爪哇語的 Temasek（淡馬錫），曾是三佛齊王國的哨所，雖一度成為貿易重鎮，後又沒落，僅留少數考古遺跡。\r\n現代新加坡之父：1819 年 1 月 28 日，英國東印度公司的斯坦福·萊佛士爵士抵達，並於同年 2 月 6 日建立首個英國據點，這一天被視為現代新加坡的誕生。當時島上僅有約 1,000 名海洋游牧民族（Orang Laut）。\r\n納入英國勢力：至 1824 年，英國東印度公司以 60,000 美金及每年 24,000 美金的津貼向柔佛蘇丹買下全島。\r\n\r\n三、 英國海峽殖民地時期\r\n地位提升：1826 年成為海峽殖民地的一部分，並於 1836 年成為首府。1867 年正式成為英國皇室直轄殖民地。\r\n貿易樞紐：憑藉位於中歐航線間的地理優勢，新加坡迅速發展為重要轉口港。1881 年全島人口已達 172,993 人。\r\n\r\n四、 二戰與日據時期\r\n淪陷：二戰期間，儘管英、澳、印聯軍在人數上佔優勢，仍不敵日軍進攻，於 1942 年 2 月投降。\r\n昭南島：日本將其更名為「昭南島」（意為「昭和時代獲得的南方島嶼」），統治直至 1945 年 9 月日本投降為止。\r\n\r\n五、 邁向獨立之路\r\n自治與建國：1945 年英國恢復統治；1959 年成立自治殖民地，李光耀帶領人民行動黨（PAP）勝選，出任首任總理。\r\n加入與退出聯邦：1963 年脫離英國獨立，與馬來亞、沙巴、砂拉越組成聯邦。然而，由於種族衝突（1964 年大動亂）及與吉隆坡中央政府的政見不合，新加坡於 1965 年 8 月 9 日被逐出聯邦。當天，馬來西亞率先承認新加坡主權。\r\n女性投票權：1947 年獲得權力，並在 1948 年及 1965 年獨立時獲得確認。\r\n\r\n六、 經濟奇蹟與近代挑戰\r\n亞洲四小龍：獨立初期面臨失業、住房短缺及資源匱乏等嚴峻考驗。在李光耀（1959-1990 在任）的領導下，新加坡在一個世代內從開發中國家躍升為工業化國家。\r\n\r\n領導人更迭：\r\n1990 年：吳作棟繼任總理，經歷了 1997 年亞洲金融風暴。\r\n2003 年：面臨 SARS 疫情與伊斯蘭祈禱團（JI）的恐怖主義威脅。\r\n2004 年：李光耀長子李顯龍接任第三任總理。','https://api.lumoguide.com/storage/uploads/20260301/AdfvsPMsF9xOp6YvQASe.png','[\"https://api.lumoguide.com/storage/uploads/20260301/AdfvsPMsF9xOp6YvQASe.png\", \"https://api.lumoguide.com/storage/uploads/20260301/hlxFllHubqsIvOcYtMNp.png\", \"https://api.lumoguide.com/storage/uploads/20260301/criv2Z4Migj2JDwqwONa.png\", \"https://api.lumoguide.com/storage/uploads/20260301/q4zzxaL9tY1FHGx8Rk4C.png\", \"https://api.lumoguide.com/storage/uploads/20260301/yzEsTfZLsj9J4ES4ZkF3.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-02-28 22:40:36','2026-02-28 22:40:49'),(11,53,3,3,'林道','Lindau',2,29,27,NULL,NULL,NULL,0,'EUR','德語','18','日耳曼','林道 (波登湖)（Lindau (Bodensee)，舊稱「波登湖中的林道」）是德國巴伐利亞邦西南部的一座中型城市。這座前帝國自由市的歷史中心以馬克西米利安大街（Maximilianstraße）為中心，坐落於波登湖東部的一個島嶼上。該島透過一座公路橋和林道鐵路堤道與陸地上的各個城區相連。\r\n\r\n林道是一座「大縣轄市」（Große Kreisstadt），也是巴伐利亞邦史瓦本行政區（Regierungsbezirk Schwaben）內同名縣份（Landkreis Lindau）的行政中心。當地的標誌性建築是位於波登湖港口的燈塔與獅子雕像。由於鄰近奧地利與瑞士，該市是許多遊客的首選目的地。自 1950 年代以來，這裡定期舉辦諾貝爾獎得主大會，提供頂尖學者與年輕科學家交流的平台。','早期歷史\r\n市中心最早的定居點位於陸地上的艾沙赫（Aeschach）舊天主教墓地附近。1878 年在此發現了羅馬定居遺跡，1888 年挖掘出一座 2 世紀帶有地暖系統（Hypokaustheizung）的羅馬別墅（villa suburbana）地基，現址為「羅馬公園」。此外，根據錢幣發現，民間普遍認為目前的「羅馬防禦工事」（Römerschanze，島上三個前子島之一，古稱“Burg”）也具有羅馬背景，該地形成了林道港口的東岸。雖然錢幣發現的證據力有限，但專家認為，像林道島這樣的天然據點，在民族大遷徙早期很可能是羅馬人或羅馬化居民的撤退避難所。\r\n\r\n修道院創立與早期城市發展\r\n林道最早於 882 年在聖加侖（St. Gallen）的一份捐贈證書中以「Lindoua」或「Lintoua」之名被提及。然而，這僅是指當時島上唯一的法人實體——林道女子修道院。根據《路德維希手冊》（Ludovicianum）記載，該院由布夏丁格家族（Burchardinger）的拉蒂亞阿達爾貝特（Adalbert von Rätien）於 810 至 820 年間創立。島上的聖彼得教堂（Peterskirche）是早期宗教中心，甚至可能在修道院建立前就是漁民教堂。\r\n原本市場位於陸地的艾沙赫，但因 1079 年「敘任權鬥爭」導致局勢動盪，出於安全考量，市場被遷往島上。\r\n\r\n林道作為帝國自由市\r\n約 1180 年修建了聖斯蒂芬教堂，1224 年方濟各會建立修道院。1274/1275 年，國王魯道夫一世確認了林道的城市權，使其正式成為帝國自由市（Reichsstadt）。林道利用其鑄幣權推出了「永恆芬尼」（Ewiger Pfennig），以穩定因頻繁更換錢幣而受干擾的貿易。\r\n林道是 1376 年成立的「史瓦本城市聯盟」創始成員。1496/97 年，皇帝馬克西米利安一世在林道老市政廳召開了帝國議會。從 15 世紀到 1826 年，著名的「米蘭信使」（又稱林道信使）往返於林道與米蘭之間。憑藉糧食、食鹽貿易與強大的波登湖船隊，市民階層積累了巨大財富。\r\n\r\n近代\r\n1500 年起，林道隸屬於史瓦本行政圈。16 世紀初鼠疫爆發，導致艾沙赫興建了專用的鼠疫病房與墓地。\r\n1528 年，林道在康斯坦茨改革者布拉勒的影響下轉向新教，並在 1529 年施派爾帝國議會中加入抗議少數派。女子修道院仍維持天主教，而方濟各會修道院則關閉。\r\n三十年戰爭期間（1646/47），林道遭瑞典軍隊圍攻，但在帝國軍指揮官沃爾夫艾格伯爵的帶領下，林道人成功擊退了瑞典人。\r\n1728 年，一場毀滅性大火摧毀了修道院區和部分老城，隨後以巴洛克風格重建。\r\n1445 年至 1761 年間，林道共有 18 人被指控為女巫，其中 9 人被處決。最後一位受害者瑪麗亞·馬德萊納於 1730 年被處死。\r\n\r\n19 世紀\r\n1803 年，因《帝國代表團主要決議》，林道失去帝國自由市地位，女子修道院被世俗化。1804 年短暫歸屬奧地利後，1805 年根據《普雷斯堡和約》被割讓給巴伐利亞。1809 年，林道曾發生反對巴伐利亞政府的武裝起義，但旋即失敗。\r\n1854 年，通往島上的鐵路堤道建成；1856 年修建了擁有獅子雕像與新燈塔的新港口——這是德國最南端的燈塔，也是巴伐利亞唯一的燈塔。\r\n\r\n20 世紀\r\n1922 年，艾沙赫、霍伊倫與羅伊廷併入林道。市長路德維希·席伯特後來成為巴伐利亞首位納粹黨籍市長，1933 年後升任巴伐利亞總理。\r\n二戰結束前夕（1945 年 4 月 30 日），法軍和平占領林道，該市倖免於空襲摧毀。戰後，林道及其縣份作為「巴伐利亞林道區」劃歸法國占領區，與美佔區的巴伐利亞隔離開來，擁有特殊的政治地位，作為連結法佔德國與法佔奧地利的橋樑。直到 1955 年 9 月，林道才重新併入巴伐利亞邦（1956 年正式生效）。\r\n儘管當地沒有大學，但自 1951 年起舉辦的**「林道諾貝爾獎得主大會」**以及「林道心理治療週」，使林道在國際科學界享有盛名。\r\n\r\n行政併入紀錄\r\n1922 年：併入 Aeschach、Hoyren、Reutin。\r\n1976 年：併入 Reitnau（由原 Oberreitnau 與 Unterreitnau 合併而成）。','https://api.lumoguide.com/storage/uploads/20260302/pdeTJwfQGMFD7KwWxNAw.png','[\"https://api.lumoguide.com/storage/uploads/20260302/pdeTJwfQGMFD7KwWxNAw.png\", \"https://api.lumoguide.com/storage/uploads/20260302/E5JYOUL3C1vNgQqjSqLh.png\", \"https://api.lumoguide.com/storage/uploads/20260302/W8p7P6pIRy26UDiOqorB.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-02 01:22:23','2026-03-02 01:22:43'),(12,54,3,3,'因特拉肯','Interlaken',2,29,28,NULL,NULL,NULL,0,'CHF','英語/德語','6123','日耳曼','因特拉肯 (Interlaken)\r\n\r\n因特拉肯是瑞士伯恩州（Bern）因特拉肯-上哈斯利行政區（Interlaken-Oberhasli）的一個市鎮及首府。\r\n該市鎮位於伯恩阿爾卑斯山北緣，座落在圖恩湖（Lake Thun）與布里恩茨湖（Lake Brienz）之間。作為當地的交通樞紐，因特拉肯是前往阿爾卑斯山名勝的重要目的地與中轉站。它是「因特拉肯度假區」的核心中心，每年吸引約 20 萬名遊客。\r\n\r\n前往少女峰的起始點\r\n因特拉肯被公認為登頂「歐洲之巔」少女峰（Jungfraujoch） 的最主要起始門戶。遊客通常從 因特拉肯東站 (Interlaken Ost) 出發，展開精彩的山區鐵路之旅：','名稱由來\r\n\r\n現今的因特拉肯於 1837 年從馬滕（Matten）市鎮中獨立，成為自治市鎮。在 1837 年至 1891 年間，該地原名為 「阿爾米勒」（Aarmühle），此名源於早期位於阿勒河畔的一座修道院磨坊。直到 1891 年，才正式更名為現今的「因特拉肯」。\r\n\r\n因特拉肯座落於圖恩湖與布里恩茨湖之間的「博德利」（Bödeli）沖積平原上。其名稱源自拉丁語「inter lacūs」，意為**「兩湖之間」**。在鄰近城鎮下塞恩（Unterseen）自 1280 年起使用的印章上，周邊刻字寫道：「S[igillum] Civitatis Inderlapen」（意為「Inderlapen 市鎮之印」）。\r\n\r\n發展歷史\r\n\r\n在中世紀晚期，當伯恩市開始掌握因特拉肯修道院、恩斯普倫倫領地（及其城堡）以及下塞恩小鎮的統治權時，「因特拉肯」一詞最初是指下塞恩城門前的區域。\r\n\r\n約於 1130 年，奧博霍芬男爵塞利格（Freiherr Seliger von Oberhofen）在圖恩湖與布里恩茨湖之間一處名為「Matten」的地方建造了一座木造祈禱室，這便是後來因特拉肯修道院的前身。該修道院隸屬於奧斯定會（Augustinerorden），約有 30 名修士與平信徒在此遵循奧斯定會規生活。1133 年，修道院獲得皇帝洛泰爾三世（Lothar III）的保護。當時阿勒河畔建有一座「阿爾米勒」（Aarmühle）磨坊，推測也是由修道院所設立。1224 年，伯恩市正式將該修道院納入其保護之下。至於與男修道院並存的女修道院，則於 1484 年關閉。\r\n\r\n宗教改革後，隨著修道院於 1528 年被廢除，因特拉肯地區轉歸伯恩管轄。當時負責該地區的伯恩地方長官（Landvogt）便居住在先前的修道院建築中。\r\n\r\n1798 年，因特拉肯成為歐伯蘭邦（Kanton Oberland）同名區的首府，但該邦在 1803 年即併回伯恩邦。自 1831 年起，因特拉肯成為因特拉肯轄區（Amtsbezirk Interlaken）的首府，該區於 2010 年併入因特拉肯-上哈斯利行政區。\r\n\r\n約於 1800 年，伯恩歐伯蘭的山岳世界開始被旅人發現與描繪，其中包括知名文人歌德、拜倫勳爵以及作曲家孟德爾頌。19 世紀下半葉，因特拉肯發展成為觀光勝地。1906 年 9 月 1 日，在維多利亞少女峰大飯店（Grand Hotel Victoria-Jungfrau）發生了一起誤殺事件，遠道而來求學的俄羅斯社會革命黨人塔季揚娜·列昂季耶娃（Tatjana Leonteva）因認錯人而槍殺了法國商人查理·米勒。\r\n\r\n1890 年通往勞特布龍嫩與格林德瓦的**伯恩歐伯蘭鐵路（BOB）建成，以及 1912 年少女峰鐵路（JB）**的通車，為因特拉肯帶來了新一波的繁榮。此外，恩斯普倫倫節（Unspunnenfeste）與《泰爾劇》（Tellspiele）對旅遊發展也至關重要；雖然這些活動通常與因特拉肯掛鉤，但《泰爾劇》實際上是在鄰近的維爾德斯維爾（Wilderswil）與馬滕（Matten）舉行，而恩斯普倫倫節目前則在因特拉肯市中心舉行。1913 年，連接圖恩湖至因特拉肯西站（Interlaken-West）的運河也正式完工。\r\n\r\n第二次世界大戰期間，因特拉肯的克蘭茨別墅（Villa Cranz，現為市鎮政府所在地）於 1941 年至 1944 年間曾作為吉桑將軍（General Guisan）的陸軍總部。當時在博德利平原上設有因特拉肯堡壘機場，周邊山壁中則建有五座砲兵堡壘。','https://api.lumoguide.com/storage/uploads/20260302/4uGfwB5DibqyF1CtGblE.png','[\"https://api.lumoguide.com/storage/uploads/20260302/4uGfwB5DibqyF1CtGblE.png\", \"https://api.lumoguide.com/storage/uploads/20260302/wRAkRiDWum5nuWqN041P.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-02 01:33:30','2026-03-02 01:34:02'),(13,57,3,3,'manarola','Manarola',2,9,60,NULL,NULL,NULL,0,'EUR','義大利語','18','義大利','Manarola','Manarola','https://api.lumoguide.com/storage/uploads/20260303/9FSR384KlGaZ3foY1O4v.png','[\"https://api.lumoguide.com/storage/uploads/20260303/9FSR384KlGaZ3foY1O4v.png\"]',2,NULL,0,0,0,0,0,0,1,'2026-03-02 20:34:49','2026-03-02 20:34:49'),(14,57,3,3,'manarola','Manarola',2,9,60,NULL,NULL,NULL,0,'EUR','義大利語','18','義大利','Manarola','Manarola','https://api.lumoguide.com/storage/uploads/20260303/zkHE4yVARFgPWOYVUmKt.png','[\"https://api.lumoguide.com/storage/uploads/20260303/zkHE4yVARFgPWOYVUmKt.png\"]',2,NULL,0,0,0,0,0,0,1,'2026-03-02 20:35:22','2026-03-02 20:42:19'),(15,57,3,3,'manarola','Manarola',2,9,60,NULL,'9.727801446944852','44.106313911951396',0,'EUR','義大利語','18','義大利','馬納羅拉 (Manarola) 是義大利利古里亞大區（Ligurien）拉斯佩齊亞省（La Spezia）里奧馬焦雷（Riomaggiore）的一個分區。它是著名的五漁村 (Cinque Terre) 之一。\n\n馬納羅拉可能是五漁村中最古老的村莊，因為村內聖羅倫佐教堂（San Lorenzo）的奠基紀錄可追溯至 1160 年。\n\n當地的方言為馬納羅拉語 (Manarolese)，與鄰近村落的方言有所不同。馬納羅拉的傳統產業為釀酒與捕魚。當地出產的葡萄酒被稱為 Sciacchetrà，古羅馬文獻中便已有關於這種名酒的記載。\n\n經濟雜誌《富比士》（Forbes）於 2025 年 9 月發布了「全球最美的 50 個村莊」名單，馬納羅拉位列第 16 名，是唯一入選的義大利村莊。','1. 古代與羅馬時期：美酒的起源\r\n雖然馬納羅拉現有的建築大多建於中世紀，但其歷史根源可追溯至羅馬時代。\r\n名字由來：學術界普遍認為 \"Manarola\" 演變自拉丁語 \"Magna Arula\"，意為「大型的小祭壇」或「大型磨盤」。\r\n釀酒傳統：古羅馬文獻曾高度讚揚當地出產的葡萄酒。這種悠久的釀酒傳統延續至今，轉化為世界知名的 Sciacchetrà 甜酒。\r\n\r\n2. 中世紀：防禦與信仰\r\n馬納羅拉被認為是五漁村中最古老的村莊，其發展與防禦海盜密不可分。\r\n遷徙歷史：最初的居民是為了躲避海盜，從內陸高地（如 Volastra）遷徙到岸邊的礁石上定居。\r\n聖羅倫佐教堂 (San Lorenzo)：村內著名的教堂建於 1338 年（亦有更早的奠基紀錄至 1160 年），屬於利古里亞哥德式風格。教堂頂部的鐘樓在古代同時兼具防禦瞭望塔的功能。\r\n防禦體系：為了抵禦北非海盜（薩拉森人）的襲擊，馬納羅拉發展出了典型的「塔樓房」（Case-Torri）建築結構，房屋相互緊靠，外部形成天然屏障。\r\n\r\n3. 熱那亞共和國時期\r\n中世紀晚期，馬納羅拉與其他五漁村村落一同納入熱那亞共和國的版圖。\r\n農業革命：在熱那亞的統治下，當地居民開始了艱苦卓絕的「梯田工程」。他們在陡峭的山坡上修築石牆，開墾出大片的葡萄園。這塑造了今日被列為世界遺產的獨特文化景觀。\r\n海上貿易：熱那亞穩定的統治促進了當地葡萄酒對外的貿易輸出。\r\n\r\n4. 19 世紀：鐵路的變革\r\n長期以來，馬納羅拉只能透過海路或險峻的山路與外界聯繫。\r\n鐵路通車 (1870年代)：熱那亞－拉斯佩齊亞鐵路的建成是馬納羅拉歷史的重大轉折。鐵路打破了地理孤立，使得當地農產品更容易運出，但也讓傳統的捕魚業比重逐漸下降。\r\n\r\n5. 20 世紀至今：從農村到世界遺產\r\n國家公園與世界遺產：1997 年，馬納羅拉隨五漁村整體被聯合國教科文組織列入世界文化遺產。1999 年，五漁村國家公園成立。\r\n旅遊經濟：隨著 20 世紀後半葉全球旅遊業的興起，馬納羅拉從一個純粹的漁村與農村，轉型為全球知名的旅遊目的地。其著名的「愛之路」（Via dell\'Amore）步道連結了馬納羅拉與里奧馬焦雷。\r\n世界最大發光聖誕馬槽：自 1961 年起，馬納羅拉每年聖誕節期間都會在山坡上佈置全世界最大的發光聖誕馬槽（Presepe），這已成為該村現代文化的新象徵。','https://api.lumoguide.com/storage/uploads/20260303/9FSR384KlGaZ3foY1O4v.png','[\"https://api.lumoguide.com/storage/uploads/20260303/9FSR384KlGaZ3foY1O4v.png\"]',2,NULL,0,0,0,0,0,0,1,'2026-03-02 21:01:07','2026-03-02 21:01:35'),(16,29,3,3,'貝希特斯加登','Berchtesgaden',2,29,27,NULL,NULL,NULL,0,'歐元','德語','8000','日耳曼人','貝希特斯加登是位於上巴伐利亞（Oberbayern）極東南端、貝希特斯加登縣境內的一個集鎮（Markt）。作為該縣南部的區域中心，它在區域規劃中隸屬於「南上巴伐利亞規劃區」。距離最近的德國大城市是慕尼黑，而鄰近的奧地利城市薩爾茨堡 (Salzburg) 也承擔了部分中心城市的功能。\r\n旅遊業的興起與挑戰\r\n\r\n旅遊起步： 19 世紀中葉，憑藉其壯麗的景點與自然景觀，貝希特斯加登成為遊客數量快速增長的旅遊目的地。\r\n二戰與納粹時期： 二戰後，旅遊業的熱度持續，起初主要是因為其轄下的**上薩爾茨堡（Obersalzberg）**曾是納粹時期的「元首禁區」。上薩爾茨堡不只是歷史遺留的「朝聖地」，直到今天，它依然是許多美國遊客前往薩爾茨堡旅遊時的固定順遊行程。\r\n現狀轉型： 自 1990 年代以來，遊客數量有所下降。因此，該鎮目前致力於推廣生態保護與更具環境永續性的旅遊模式，以塑造新的品牌形象。','歷史起源與鹽業發展\r\n\r\n首次記載： 該地最早在 1102 年至 1105 年間作為修道院定居點「berthercatmen」被提及。\r\n\r\n經濟支柱： 1156 年，當地被授予森林管轄權，隨後獲得了鹽和金屬的開採權。鹽礦與金屬採掘帶領了當地的第一次經濟繁榮，使其發展成為具規模的集市。\r\n\r\n獨立主權： 奧斯定會教士長將其擴大為領地的首府。從 1559 年到 1803 年，這裡曾是「貝希特斯加登親王主教轄區」（Fürstpropstei Berchtesgaden）的政教中心，統治著這個雖小但直屬帝國（Reichsunmittelbar）的親王領地。','https://api.lumoguide.com/storage/uploads/20260304/mlpFdmVEYGXcmn0Rybf4.png','[\"https://api.lumoguide.com/storage/uploads/20260304/mlpFdmVEYGXcmn0Rybf4.png\", \"https://api.lumoguide.com/storage/uploads/20260304/JJqfZbvlCj74txotNAhz.png\", \"https://api.lumoguide.com/storage/uploads/20260304/6dYaepIQwDzCCMX0Azxn.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-03 21:15:34','2026-03-03 23:09:31'),(17,73,3,3,'成都','Chengdu',1,5,69,NULL,'104.06325160762236','30.573032625389374',0,'人民幣','漢語/四川方言','約2126萬','漢族','成都（Chéngdū，德語舊譯：Tschengdu）是中國四川省的省會，也是全國 15 座副省級城市之一。其簡稱為「蓉」（Róng）。\r\n\r\n人口與地位\r\n\r\n根據 2020 年人口普查數據，成都市及其轄區（都會區）的總人口已達 20,937,757 人。在 2010 年的統計中，約有 500 萬人居住在九個市轄區內，另有 900 萬人居住在周邊區域。成都與重慶並列，已發展成為中國西部的經濟中心。\r\n\r\n生活品質\r\n\r\n成都在中國以其悠閒的生活步調聞名。根據《中國日報》（China Daily）2006 年的報導，成都在「中國最宜居城市」評選中位居第四名。','早期歷史與「成都」之名\r\n\r\n地理優勢：兩千多年來，成都是中國西部與西南部的文化中心。由於北有秦嶺山脈阻隔，成都在歷史上多次成為獨立蜀地的割據政權首都。\r\n\r\n命名由來：公元前 4 世紀初，古蜀國遷都至此。參考周朝遷都「一年成邑，二年成都」的典故，將其命名為「成都」（意為：成為國都）。\r\n\r\n秦代統治與水利：公元前 316 年秦國滅蜀，成都併入中國版圖。公元前 251 年都江堰水利工程的建成，為成都平原豐富的農業產出奠定了基礎。\r\n\r\n漢唐盛世：錦官城與文人墨客\r\n\r\n漢代工商業：漢代時成都已透過棧道與長安連接。當時以鑄鐵、鹽井、漆器及蜀錦聞名。因蜀錦產量驚人，設有專門官員（錦官）管理，故得名「錦官城」。漢代成都人口達 7.6 萬，與長安、洛陽等並列為六大都市。\r\n\r\n三國與唐代：三國時期，劉備在此建立蜀漢（221–263）。唐代時，大詩人李白與杜甫皆曾居於此。杜甫於 760 至 765 年間在成都過著清貧生活，留下了著名的「杜甫草堂」。安史之亂時，唐玄宗亦曾逃亡至成都避難。\r\n\r\n五代至明清：芙蓉城與經濟創新\r\n\r\n芙蓉城之名：五代十國時期，後蜀皇帝孟昶在城牆上遍植木芙蓉，成都因此獲得「蓉城」（芙蓉城）的雅號。\r\n\r\n經濟與印刷先驅：成都是世界上最早發明印刷術與紙幣的地區之一。9 世紀起出現茶鹽貿易的匯票，1024 年成都出現了世界上第一種官辦紙幣「交子」。此外，成都還是印刷中心，曾大規模印刷儒家經典與佛經。\r\n\r\n明末浩劫：明末農民起義領袖張獻忠於 1644 年攻佔成都建立「大西」政權，實行恐怖統治。1646 年撤退前下令摧毀成都，隨後清軍入城。\r\n\r\n現代史與展望\r\n\r\n國共內戰最後一站：1949 年，成都是國民黨軍隊在中國大陸最後撤守的城市。同年 12 月 10 日，共產黨軍隊接管成都。\r\n\r\n1989 年動盪：1989 年 6 月 4 日北京天安門事件後，成都也發生了抗議與流血衝突。\r\n\r\n未來規劃：成都目前正計畫在郊外建設名為「Great City」的示範城鎮，旨在透過完善規劃，讓 8 萬名居民能完全無需使用私人汽車生活。','https://api.lumoguide.com/storage/uploads/20260306/GhvYDApYpFqJdPWaS4kA.png','[\"https://api.lumoguide.com/storage/uploads/20260306/GhvYDApYpFqJdPWaS4kA.png\", \"https://api.lumoguide.com/storage/uploads/20260307/UxKW4DCN7Dz37sNCJ0Ak.png\", \"https://api.lumoguide.com/storage/uploads/20260307/Dg3OyD2PRKjdxVf4Wi4A.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-07 02:08:25','2026-03-07 02:10:23'),(18,71,3,3,'上海','Shanghai',1,5,69,NULL,'121.46636821588007','31.230924211479564',0,'人民幣','漢語/上海話','約2480萬','華人','上海是中華人民共和國最重要的工業城市，也是全球最大的城市之一。\r\n地理與人口結構\r\n上海由市中心（約 1,500 萬居民）及周邊延伸至 50 公里外的多個市轄區組成。市區建築密度極高，而郊區則保有較多鄉村特色。根據 2020 年人口普查，上海總人口達 24,870,895 人。在 2010 年的統計中，約 1,590 萬人為持有正式戶口（Hùkǒu）的常住居民，另有 710 萬人為持有暫住證的流動人口。\r\n上海是直轄市，行政地位與省級相同。其管轄面積約 6,340.5 平方公里（2012 年數據），且隨著長江口灘塗的不斷填海造陸，面積正持續擴大。\r\n\r\n經濟地位\r\n上海港是全球物流的樞紐。截至 2022 年，其貨櫃吞吐量達 4,728 萬標準箱（TEU），穩居世界第一大貨櫃港。若以貨物總吞吐量計算（2012 年達 7.36 億噸），它同樣位居全球首位。此外，上海也是中國重要的交通樞紐、文化與教育中心，擁有眾多大學、科研機構、劇院與博物館。\r\n\r\n名稱由來與別稱\r\n「上海」二字在中文裡的組合意為「去往海上」，而非字面上常見但錯誤的「海上的城市」（後者應為「海上」）。\r\n\r\n常見的別稱包括：\r\n「東方巴黎」（Paris des Ostens）：形容其繁華與洋派。\r\n「東方明珠」（Perle des Orients）。\r\n「龍頭」（Drachenkopf-Metropole）：象徵其在中國經濟中的領航地位。\r\n\r\n此外，上海有兩個官方簡稱：\r\n「滬」（Hù）：源於古代的一種竹製捕魚工具，現亦用於車牌代碼。\r\n「申」（Shēn）：源於戰國時期春申君的封地。','早期發展與貿易崛起\r\n\r\n早期聚落：上海地區的定居史可追溯至公元前 4000 年。960 年首次出現「上海」作為村莊的記載。\r\n\r\n貿易樞紐：隨著長江三角洲經濟發展，上海地位提升。1554 年，上海築起十公尺高的城牆。至清代（1644–1911），當地已形成類似歐洲行會的強大商人公會，掌握城內的經濟與部分政治權力。\r\n\r\n外國租界時期（1842–1945）\r\n\r\n被迫開放：1842 年《南京條約》強迫上海開埠，英國將其選為「通商口岸」，並視其為東亞最重要的市場。隨後法國（1847）、美國（1863）與日本（1895）紛紛進駐，形成「公共租界」與各自的特權飛地。\r\n\r\n動盪與繁榮：1900 年代初，上海人口破百萬，成為外國勢力與罪犯（如著名的「青幫」）混雜之地。在太平天國與義和團運動期間，大量難民湧入租界，形成中國最早的城市無產階級。\r\n\r\n世界都會：1920 年代上海成為充滿冒險與財富的「世界之都」，也是中國現代公民社會的搖籃。1921 年，中國共產黨在上海成立。\r\n\r\n抗戰時期：1932 年（一二八事變）與 1937 年（淞滬會戰），日本對上海發動軍事攻擊。雖然租界內設立了國際安全區保護平民，但市區遭到重創。\r\n\r\n二戰中的猶太避難所\r\n\r\n生命方舟：1938 至 1941 年間，約 1.8 萬名德國與奧地利猶太人為逃避納粹迫害來到上海（當時免簽證）。儘管 1943 年起被日軍強迫遷入「虹口隔都」（Shanghaier Ghetto），但他們大多在此躲過大屠殺並存活下來。\r\n\r\n共產黨執政時期\r\n\r\n政權更迭：1949 年 5 月 27 日毛澤東領導的共產黨軍隊進入上海，接管這座亞洲最重要的經濟中心。隨後政府採取了強硬的社會改造與資本清算措施，許多外資撤往香港。\r\n\r\n政治風暴：1966 年文化革命從上海發起，並出現了短暫的「上海公社」。1976 年毛澤東逝世後，上海成為「四人幫」奪權的最後據點。\r\n\r\n經濟騰飛：1980 年代，在曾任市長的江澤民與朱鎔基等人推動下，上海開啟了新一輪的經濟騰飛，恢復了其作為國際金融與貿易大都市的地位。\r\n\r\n經濟騰飛與現代化\r\n\r\n浦東崛起：1980 年代中期，上海被賦予中國現代化先鋒的使命。1990 年設立浦東新區，啟動「新外灘」開發計畫，引入巨額外資。\r\n\r\n產業轉型：上海轉向高科技領域，發展生物技術、資訊科技與微電子，並成為國際金融機構的重鎮。目前上海擁有中國最高建築——上海中心大廈（632 米），並擁有全球首個商用高速磁浮列車（Transrapid）連接浦東機場。','https://api.lumoguide.com/storage/uploads/20260306/NAl2GMeRnQFep47ktTTg.png','[\"https://api.lumoguide.com/storage/uploads/20260306/NAl2GMeRnQFep47ktTTg.png\", \"https://api.lumoguide.com/storage/uploads/20260306/HirUNN4Zz92Z3y77Yufw.png\", \"https://api.lumoguide.com/storage/uploads/20260307/TOQaL5Ky5hDHlqVq5brZ.png\", \"https://api.lumoguide.com/storage/uploads/20260307/omNsHk9y4w47F7lxVHJl.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-07 02:17:27','2026-03-07 02:22:01'),(19,43,3,3,'廈門','Xiamen',1,5,69,NULL,'118.0923806820658','24.47823791467448',0,'人民幣','廈門話（閩南語）','100萬','漢族為主','廈門市，別稱鷺島，簡稱廈或鷺，是位於中華人民共和國福建省東南部的城市，是中國東南沿海重要的中心城市、最早對外開放的四個經濟特區之一，亦屬計劃單列市及副省級城市。廈門市和泉州市、漳州市接壤，與金門縣隔海對望，是由廈門島、鼓浪嶼等島與海滄、集美、同安、翔安等沿海地區組成的海灣型城市。全市下轄思明、湖裡、集美、海滄、同安、翔安六個行政區，是國務院批復的現代海洋城市、國際性綜合交通樞紐城市。\r\n廈門市是中國著名的僑鄉、亞洲重要的交通樞紐：廈門港為中國第7大、世界第13大集裝箱港口，廈門高崎國際機場是中國第8大出入境空港，第4大國際及地區中轉空港。此外，廈門是著名的風景旅遊城市，有「城在海上，海在城中」的美譽，著名景點有鼓浪嶼（2017年被列為世界文化遺產）、萬石山、集美學村、南普陀寺、廈門大學等。2024年廈門市被GaWc評為Beta級的世界城市。','一、 古代與命名（晉代－明代）\r\n\r\n同安立縣： 西晉（282年）始設同安縣，轄今廈門與金門。\r\n\r\n早期名稱： 唐代稱「新城」，後因產稻碩穗改稱「嘉禾嶼」。\r\n\r\n廈門由來： 明洪武二十年（1387年）設防倭要塞，雅稱「廈門」，意為大廈之門。\r\n\r\n二、 近代爭奪與通商（明末清初－民國）\r\n\r\n明鄭時期： 鄭成功改設「思明州」，以此為基地征服台灣。清軍與明鄭多次拉鋸奪島。\r\n\r\n通商口岸： 1689年開啟對英茶葉直出口；1842年《南京條約》後正式開港通商。\r\n\r\n租界與分治： 英、日等國在鼓浪嶼及廈門島設立租界。\r\n\r\n行政演變： 1935年正式設廈門市。抗戰期間曾遭日軍佔領，更名「廈門特別市」。\r\n\r\n三、 行政調整與擴張（1949年－1970年代）\r\n\r\n政權更迭： 1949年10月解放軍攻克廈門，成立市人民政府。\r\n\r\n轄區變更： 1950年代起，陸續將集美、灌口、同安、海滄等周邊區域由同安縣或龍溪縣劃歸廈門市管轄，形成今日地圖雛形。\r\n\r\n四、 改革開放與現代化（1980年至今）\r\n\r\n特區成立： 1980年設立全國首批經濟特區，1984年範圍擴大至全島。\r\n\r\n地位升格： 1988年批准為計劃單列市，1994年定為副省級市，並獲得特區立法權。\r\n\r\n區域調整： 2003年完成重大行政重組，撤併鼓浪嶼與開元區入思明區，析設翔安區，並將經濟特區擴展至全市。','https://api.lumoguide.com/storage/uploads/20260227/DNHzNaEFUTa52dSNuNij.png','[\"https://api.lumoguide.com/storage/uploads/20260227/DNHzNaEFUTa52dSNuNij.png\", \"https://api.lumoguide.com/storage/uploads/20260227/dfm6UMRH8CA7ISD8uaSu.png\", \"https://api.lumoguide.com/storage/uploads/20260227/MDW93JeShhmGtoXgDVfb.png\", \"https://api.lumoguide.com/storage/uploads/20260307/eRiJGzCPRoOtAZ4y8dfl.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-07 02:20:49','2026-03-07 02:22:33'),(20,71,3,3,'上海','Shanghai',1,5,69,NULL,'121.46636821588007','31.230924211479564',0,'人民幣','漢語/上海話','約2480萬','華人','上海是中華人民共和國最重要的工業城市，也是全球最大的城市之一。\r\n地理與人口結構\r\n上海由市中心（約 1,500 萬居民）及周邊延伸至 50 公里外的多個市轄區組成。市區建築密度極高，而郊區則保有較多鄉村特色。根據 2020 年人口普查，上海總人口達 24,870,895 人。在 2010 年的統計中，約 1,590 萬人為持有正式戶口（Hùkǒu）的常住居民，另有 710 萬人為持有暫住證的流動人口。\r\n上海是直轄市，行政地位與省級相同。其管轄面積約 6,340.5 平方公里（2012 年數據），且隨著長江口灘塗的不斷填海造陸，面積正持續擴大。\r\n\r\n經濟地位\r\n上海港是全球物流的樞紐。截至 2022 年，其貨櫃吞吐量達 4,728 萬標準箱（TEU），穩居世界第一大貨櫃港。若以貨物總吞吐量計算（2012 年達 7.36 億噸），它同樣位居全球首位。此外，上海也是中國重要的交通樞紐、文化與教育中心，擁有眾多大學、科研機構、劇院與博物館。\r\n\r\n名稱由來與別稱\r\n「上海」二字在中文裡的組合意為「去往海上」，而非字面上常見但錯誤的「海上的城市」（後者應為「海上」）。\r\n\r\n常見的別稱包括：\r\n「東方巴黎」（Paris des Ostens）：形容其繁華與洋派。\r\n「東方明珠」（Perle des Orients）。\r\n「龍頭」（Drachenkopf-Metropole）：象徵其在中國經濟中的領航地位。\r\n\r\n此外，上海有兩個官方簡稱：\r\n「滬」（Hù）：源於古代的一種竹製捕魚工具，現亦用於車牌代碼。\r\n「申」（Shēn）：源於戰國時期春申君的封地。','早期發展與貿易崛起\r\n\r\n早期聚落：上海地區的定居史可追溯至公元前 4000 年。960 年首次出現「上海」作為村莊的記載。\r\n\r\n貿易樞紐：隨著長江三角洲經濟發展，上海地位提升。1554 年，上海築起十公尺高的城牆。至清代（1644–1911），當地已形成類似歐洲行會的強大商人公會，掌握城內的經濟與部分政治權力。\r\n\r\n外國租界時期（1842–1945）\r\n\r\n被迫開放：1842 年《南京條約》強迫上海開埠，英國將其選為「通商口岸」，並視其為東亞最重要的市場。隨後法國（1847）、美國（1863）與日本（1895）紛紛進駐，形成「公共租界」與各自的特權飛地。\r\n\r\n動盪與繁榮：1900 年代初，上海人口破百萬，成為外國勢力與罪犯（如著名的「青幫」）混雜之地。在太平天國與義和團運動期間，大量難民湧入租界，形成中國最早的城市無產階級。\r\n\r\n世界都會：1920 年代上海成為充滿冒險與財富的「世界之都」，也是中國現代公民社會的搖籃。1921 年，中國共產黨在上海成立。\r\n\r\n抗戰時期：1932 年（一二八事變）與 1937 年（淞滬會戰），日本對上海發動軍事攻擊。雖然租界內設立了國際安全區保護平民，但市區遭到重創。\r\n\r\n二戰中的猶太避難所\r\n\r\n生命方舟：1938 至 1941 年間，約 1.8 萬名德國與奧地利猶太人為逃避納粹迫害來到上海（當時免簽證）。儘管 1943 年起被日軍強迫遷入「虹口隔都」（Shanghaier Ghetto），但他們大多在此躲過大屠殺並存活下來。\r\n\r\n共產黨執政時期\r\n\r\n政權更迭：1949 年 5 月 27 日毛澤東領導的共產黨軍隊進入上海，接管這座亞洲最重要的經濟中心。隨後政府採取了強硬的社會改造與資本清算措施，許多外資撤往香港。\r\n\r\n政治風暴：1966 年文化革命從上海發起，並出現了短暫的「上海公社」。1976 年毛澤東逝世後，上海成為「四人幫」奪權的最後據點。\r\n\r\n經濟騰飛：1980 年代，在曾任市長的江澤民與朱鎔基等人推動下，上海開啟了新一輪的經濟騰飛，恢復了其作為國際金融與貿易大都市的地位。\r\n\r\n經濟騰飛與現代化\r\n\r\n浦東崛起：1980 年代中期，上海被賦予中國現代化先鋒的使命。1990 年設立浦東新區，啟動「新外灘」開發計畫，引入巨額外資。\r\n\r\n產業轉型：上海轉向高科技領域，發展生物技術、資訊科技與微電子，並成為國際金融機構的重鎮。目前上海擁有中國最高建築——上海中心大廈（632 米），並擁有全球首個商用高速磁浮列車（Transrapid）連接浦東機場。','https://api.lumoguide.com/storage/uploads/20260306/NAl2GMeRnQFep47ktTTg.png','[\"https://api.lumoguide.com/storage/uploads/20260306/NAl2GMeRnQFep47ktTTg.png\", \"https://api.lumoguide.com/storage/uploads/20260306/HirUNN4Zz92Z3y77Yufw.png\", \"https://api.lumoguide.com/storage/uploads/20260307/TOQaL5Ky5hDHlqVq5brZ.png\", \"https://api.lumoguide.com/storage/uploads/20260307/omNsHk9y4w47F7lxVHJl.png\", \"https://api.lumoguide.com/storage/uploads/20260308/w27LI8lI5aJfEn14pyyI.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-07 22:56:13','2026-03-07 23:48:56'),(21,28,3,3,'月亮湖（蒙德塞）','Mondsee',2,29,20,NULL,'13.34354570909751','47.85583068000424',0,'歐元','德語','3900','日耳曼','蒙德湖市擁有 3,940 名居民（截至 2025 年 1 月 1 日），位於上奧地利州的薩爾茨卡默古特地區，坐落在同名湖畔，其南岸部分與薩爾茨堡州接壤。','在蒙德湖畔的塞湖和沙夫林附近，人們在水下發現了定居點的遺跡。人們挖掘出了大量新石器時代的陶器、石器和骨器，並將其視為樁屋文化的遺跡。科學家們根據蒙德湖的主要發現地點，將其命名為蒙德湖文化。該文化可追溯至公元前 2800 年至 1800 年左右，範圍涵蓋上奧地利州的大部分地區和薩爾茨堡的部分地區。最新研究表明，這些是原始的陸地定居點，後來因湖水水位上升而淹沒在水中。蒙德湖地區博物館擁有豐富的樁屋收藏。\r\n羅馬時期，這裡曾有一個定居點，考古發現證明，一條道路將它與羅馬時期的薩爾茨堡——尤瓦武姆連接起來。600 年左右，巴伐利亞人開始在蒙德湖地區定居，並砍伐了森林。748 年，來自阿吉洛芬家族的巴伐利亞公爵奧迪洛創建了蒙德湖修道院。從那時起，修道院就對該地區的精神文化與經濟發展產生了深遠的影響。\r\n該地區最初位於巴伐利亞公國東部，在 1506 年的蘭茨胡特繼承戰爭後，與蒙德塞地區一起併入奧地利大公國。同年，皇帝馬克西米利安將蒙德塞地區抵押給薩爾茨堡大主教。60 年後，回購條款才得以實施，蒙德湖地區於 1565 年歸屬恩斯河以北的奧地利。拿破崙戰爭期間，該地區在 1809 年至 1816 年間再次被併入巴伐利亞。\r\n1791 年，在皇帝利奧波德二世的統治下，修道院被廢除。\r\n拿破崙時期，該地區再次歸屬巴伐利亞。1810 年，巴伐利亞陸軍元帥卡爾·菲利普·馮·維德獲得了廢棄的蒙德湖修道院（位於蘇本和格萊因克附近），將其作為自己的城堡。即使在 1816 年該地區歸還奧地利後，維德仍然保留了對該地區的所有權，並竭盡全力促進該地區的發展（修建道路、開始生產蒙德湖奶酪等）。\r\n自 1867 年以來，蒙德湖就開始發展旅遊業，1872 年首艘蒸汽船開始運航。1891 年，該地通過一條支線與薩爾茨卡默古特地方鐵路（1957 年廢棄）相連。','https://api.lumoguide.com/storage/images/20251202/f94a6f7cce8ebbfc4e976320fe8b1dc0.JPG','[\"https://api.lumoguide.com/storage/images/20251202/f94a6f7cce8ebbfc4e976320fe8b1dc0.JPG\", \"https://api.lumoguide.com/storage/images/20251202/f30f6ec4a3317caf13fefbcea6952cd7.JPG\", \"https://api.lumoguide.com/storage/uploads/20251205/0t16Km8XZdak4ncgZRmy.png\", \"https://api.lumoguide.com/storage/uploads/20260309/moNc0fmPep02D7xA6btf.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-09 04:08:12','2026-03-09 04:24:06'),(22,86,3,3,'基姆湖畔普林','Prien am Chiemsee',2,29,27,NULL,'12.352231295878424','47.85677081274525',0,'EUR','德語','約1.1萬','日耳曼','基姆湖（Chiemsee）常被稱為「巴伐利亞之海」，是巴伐利亞州面積最大的湖泊。\r\n規模與地位\r\n全德排名：以 79.9 平方公里的面積計算，它是繼波登湖（Bodensee）和米里茨湖（Müritz）之後的德國第三大湖。\r\n蓄水量與湖岸線：湖水體積約為 2.048 立方公里。雖然面積大，但其蓄水量僅約為巴伐利亞另一名湖——斯塔恩貝格湖（Starnberger See）的三分之二。\r\n周長：湖岸線長 63.96 公里，若加上島嶼的海岸線，總長度達 83 公里。\r\n\r\n湖中島嶼\r\n湖中主要有三座島嶼，行政上共同組成了羅森海姆縣（Landkreis Rosenheim）下的基姆湖市鎮：\r\n男島（Herreninsel）：面積最大（238 公頃）。\r\n女島（Fraueninsel）：面積 15.5 公頃。\r\n菜島（Krautinsel）：面積 3.5 公頃。\r\n此外還有一座極小的無人島 Schalch（僅 22 平方公尺）。\r\n基姆湖畔普林（Prien am Chiemsee）上船點\r\n行政歸屬\r\n基姆湖本身（水域部分）屬於特勞恩施泰因縣（Landkreis Traunstein）管轄的基姆湖非建制地區。','基姆湖畔普林（Prien am Chiemsee）\r\n\r\n一、 早期歷史與市鎮建立\r\n起源：名稱具凱爾特語淵源，原意為「橋樑之地」。\r\n羅馬與中世紀：區內 Trautersdorf 有羅馬定居點遺跡。普林於 12 世紀中葉（約 1158 年）作為法爾肯斯坦伯爵的行政地建立。\r\n建制：1818 年成為獨立政治市鎮，1897 年升格為市場鎮（Markt）。\r\n\r\n二、 觀光業的興起（19–20 世紀）\r\n兩大轉折：1860 年羅本海姆－薩爾茨堡鐵路通車，以及 1886 年海倫基姆湖宮（國王路德維希二世的宮殿）開放，使普林成為旅遊勝地。\r\n基姆湖鐵路：1887 年建造的傳統小鐵路至今仍在旅遊旺季以蒸氣火車運行，連結車站與碼頭。\r\n憲法搖籃：1948 年，普林對岸的男島召開了海倫基姆湖憲法會議，為今日德國《基本法》奠定了基礎。\r\n\r\n三、 普林猶太兒童營（1946–1948）\r\n特殊任務：二戰後，美軍在普林的「海灘飯店」為失去家長的流離失所者（DP）設立了兒童中心。\r\n定位轉變：起初對所有受害者開放，後期成為以猶太兒童為主的機構（高峰期約 269 人）。\r\n教育與去向：營內設有塔木德學校與清真（Kosher）廚房。由於此地受非錫安主義組織（如加拿大猶太國會）引導，多數青少年最後選擇移居美國或加拿大，而非以色列。','https://api.lumoguide.com/storage/uploads/20260309/ia55CxhMoXREmSKrP9vG.png','[\"https://api.lumoguide.com/storage/uploads/20260309/ia55CxhMoXREmSKrP9vG.png\", \"https://api.lumoguide.com/storage/uploads/20260309/d4ab9TAuOAPLEb9C9ZBD.png\", \"https://api.lumoguide.com/storage/uploads/20260311/M8wxdS8XbbRUDMPjz0oz.png\", \"https://api.lumoguide.com/storage/uploads/20260311/iA30j7tu99csZMT0IdVW.png\", \"https://api.lumoguide.com/storage/uploads/20260311/pucAze1v0NuR86tkM3gq.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-11 01:43:39','2026-03-11 01:46:35'),(23,98,3,3,'麗江','Lijiang',1,5,69,NULL,NULL,NULL,0,'RMB','漢語','30萬','雲南','sh h','s j j','https://api.lumoguide.com/storage/uploads/20260311/TjjCTKnOipGIfGEa9vrX.png','[\"https://api.lumoguide.com/storage/uploads/20260311/TjjCTKnOipGIfGEa9vrX.png\", \"https://api.lumoguide.com/storage/uploads/20260311/UoMJ1Fq49tbMBW2TPFfU.png\", \"https://api.lumoguide.com/storage/uploads/20260311/L7GpKxQFfJK75k49Pnow.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-11 11:34:19','2026-03-11 11:35:10'),(24,108,3,3,'錦州','JinZhou',1,5,69,NULL,'121.12461648307851','41.09500386707949',0,'RMB','漢語','約270萬','漢族為主','1. 地理戰略位置\r\n遼西走廊要衝： 錦州位於遼西走廊，這是連接華北與東北地區陸路交通的必經之地，地理戰略地位極其重要，也是遼西地區的經濟中心。\r\n\r\n海岸資源： 錦州坐落於遼東灣北岸，擁有近 98 公里的海岸線，其港口——錦州港，是中國緯度最北的海港。\r\n\r\n2. 人口與行政區劃\r\n城市規模： 截至 2020 年普查，全市人口約 270 萬人，其中中心城區（含凌海市）的都市區人口約 152 萬人，是遼寧省人口第五多的城市。\r\n管轄範圍： 總轄區面積約 9,989 平方公里，大部分區域屬於鄉村地區。\r\n\r\n錦州因「遼西走廊」的特殊地理位置，在中國歷史上（特別是古代軍事防禦與近代戰爭中）始終扮演著關鍵角色。','1. 古代歷史：戰略要地的更迭\r\n名稱變遷： 最初名為「徒河」（Tuhe），在戰國時期屬燕國領土。之後歷經秦、漢、三國、隋唐等不同政權統治，行政歸屬頻繁調整（如昌黎郡、營州、柳城郡等）。\r\n唐代重要性： 在唐朝時期，這裡是「安東都護府」的所在地，顯示了其在東北地區的行政與軍事地位。\r\n正式定名： 「錦州」一名始於遼代。後在金、元、明、清各朝代中，隨著管轄區劃（如東京路、遼東都司、奉天府等）不斷更替，曾被改稱為「錦縣」（Jinxian）。\r\n\r\n2. 近代：戰火中的關鍵節點\r\n交通咽喉： 錦州地處東北進入關內（經由山海關）的主要陸路通道，因此在共和國時期與國共內戰中，成為各方爭奪的軍事關鍵。\r\n抗戰與內戰衝突：\r\n1945 年： 國軍將領杜聿明攻佔錦州，切斷了中共部隊進入關內的通道，促成了當時的短暫停火。\r\n遼瀋戰役（1948 年）： 這是錦州歷史上最慘烈的時期之一。當時蔣介石下令封鎖錦州，不許難民南逃，導致難民在城北大凌河遭遇軍隊射殺。最終，林彪指揮的解放軍於 1948 年 9 月攻佔錦州，奠定了在東北戰場的勝局。\r\n\r\n3. 現代地位：省會與地級市\r\n短暫的省會： 1949 年中華人民共和國成立後，錦州曾作為新設立的「遼西省」省會。\r\n歸屬遼寧： 1954 年，隨著遼西省與遼東省合併為遼寧省，錦州歸入遼寧省轄下，至今仍為該省重要的地級市與經濟中心。','https://api.lumoguide.com/storage/uploads/20260314/fdwPyXBRUcRneGIKbTgy.png','[\"https://api.lumoguide.com/storage/uploads/20260314/fdwPyXBRUcRneGIKbTgy.png\", \"https://api.lumoguide.com/storage/uploads/20260314/GuL2jVnWD8kkw3TxlFOq.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-14 00:55:30','2026-03-14 00:58:25'),(25,93,3,3,'赫瓦爾','Hvar',2,17,47,NULL,'16.445028538199175','43.16148946596634',0,'EUR','克羅地亞語','3979','斯拉夫','赫瓦爾（Hvar）城市簡介\r\n\r\n赫瓦爾（當地克羅埃西亞方言稱為 Hvor 或 For；希臘語：Pharos；拉丁語：Pharina；義大利語：Lesina）是位於克羅埃西亞斯普利特-達爾馬提亞縣（Split-Dalmatien）、赫瓦爾島上的一座城市與港口。該市是天主教赫瓦爾教區的所在地。\r\n\r\n根據 2011 年的人口統計，赫瓦爾全鎮人口為 4,251 人，其中市區人口為 3,771 人，是該島上最大的城市。城市坐落於島嶼南側的一處海灣中，與島上的斯塔里格勒（Stari Grad）和耶爾薩（Jelsa）兩市相對。\r\n\r\n赫瓦爾市的轄區範圍除了市區外，還包含以下村鎮：布魯斯耶（Brusje）、雅戈德納（Jagodna）、馬洛格拉布列（Malo Grablje）、米爾納（Milna）、斯韋塔內德耶爾亞（Sveta Nedjelja）、韋洛格拉布列（Velo Grablje）以及扎拉切（Zaraće）。\r\n\r\n赫瓦爾是亞得里亞海非常受歡迎的旅遊目的地，以其歷史悠久的港口與美麗的島嶼風光聞名。','古代起源與希臘羅馬時期\r\n\r\n赫瓦爾鎮最早的已知定居點是伊利里亞人（Illyrian）的聚落，位於城鎮廣場北側的山坡上；當時那裡是一個深入內陸的小海灣，其位置約在今日大教堂所在之處。現今的西班牙堡壘（Spanish Fortress）遺址曾是一座山頂堡壘，從當地出土的陶器證明，該地自公元前 8 世紀起就已進行長途貿易。\r\n\r\n公元前 384 年，古希臘人在島嶼北岸建立了法羅斯（Faros）定居點，以便控制周邊肥沃的農業區（現稱「斯塔里格勒平原」）。據推測，當時在今日赫瓦爾鎮的所在地，可能同時存在另一個名為赫拉克利亞（Heraclea）的希臘聚落。到了公元前 2 世紀，隨著古羅馬人的到來，島上的居住地進一步擴張，主要以鄉村形式發展，依賴於羅馬式別墅（villae rusticae）。7 至 8 世紀斯拉夫人抵達後，因海岸盜匪橫行，居民被迫搬遷至內陸，中世紀期間人口多集中於遠離海岸的村莊以求安全。\r\n\r\n威尼斯帝國的保護與繁榮\r\n\r\n經歷了動盪時期後，島民於 1278 年向威尼斯帝國尋求保護。協議規定，南部的赫瓦爾定居點需擴建並加固，作為威尼斯艦隊的安全基地。赫瓦爾隨之成為新的行政中心，並改名為「萊西納」（Lesina），而古希臘城市則被稱為「奇塔韋基亞」（Cittavecchia，意即「老城」或「斯塔里格勒」）。赫瓦爾成為獨立公社政府中心、總督駐地及教區（包含赫瓦爾及鄰近的布拉奇島與維斯島）的總部。威尼斯人委託建造了新堡壘、城牆及公共建築，隨著名利雙收，村莊也逐漸沿著海岸線建立起來。\r\n\r\n15 世紀時，城鎮因老城牆範圍太小而向南方的山坡擴張。當時的中世紀城鎮以東部的大教堂為界，西部則為軍火庫、總督府與碼頭。赫瓦爾成為島上的經濟、政治與文化中心，在威尼斯航運中扮演關鍵角色。\r\n\r\n16 世紀後的動盪與變遷\r\n\r\n16 世紀重回動盪，貴族與市民衝突不斷，加上鄂圖曼土耳其帝國在對岸的威脅，導致該市屢遭攻擊。1571 年，赫瓦爾在土耳其艦隊前往「勒班陀戰役」途中遭到劫掠，幸得堡壘庇護才倖免於難。然而城鎮重建剛完成，1579 年堡壘內的火藥庫又因雷擊引發爆炸，造成進一步破壞。赫瓦爾現今許多公共建築皆源於那次爆炸後的重建。\r\n\r\n衰落、哈布斯堡統治與現代觀光\r\n\r\n1776 年，威尼斯人將海軍基地遷往大陸的科托爾（Kotor），赫瓦爾隨之陷入衰落。簡而言之，赫瓦爾於 1278 至 1358 年，以及 1420 至 1797 年間皆隸屬於威尼斯共和國。1797 年拿破崙控制威尼斯後，在短暫的法國統治時期結束後，赫瓦爾於 19 世紀初歸入奧地利哈布斯堡帝國。這段時期是該鎮經濟與文化生活極為發達的黃金年代。1868 年，「赫瓦爾衛生協會」（The Hygienic Association of Hvar）成立，正式開啟了該地旅遊服務的發展之路。','https://api.lumoguide.com/storage/uploads/20260310/JsaGennGtKaDvD5iqqWW.png','[\"https://api.lumoguide.com/storage/uploads/20260310/JsaGennGtKaDvD5iqqWW.png\", \"https://api.lumoguide.com/storage/uploads/20260315/gC7LD9jFprUNNTAjBxjb.png\", \"https://api.lumoguide.com/storage/uploads/20260315/rQdAN8ofpxvGUs9MOpuH.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-14 23:53:01','2026-03-15 00:18:17'),(26,80,3,3,'德累斯頓','Dresden',2,29,27,NULL,'13.76033807198696','51.055482732049164',0,'EUR','德語','約56萬','日耳曼','城市概況：薩克森邦的政治與文化核心\r\n基本資訊：德勒斯登是薩克森自由邦的首府。人口約 56 萬，是薩克森邦第二大城（僅次於萊比錫），也是德國第十二大城市。\r\n政治中心：身為薩克森邦政府與議會的所在地，它是該邦的政治權力中樞。\r\n教育與研究：擁有聲譽卓著的德勒斯登工業大學（TU Dresden）以及多所藝術、音樂與技術學院。\r\n經濟與交通：歐洲的「矽薩克森」\r\n產業優勢：德勒斯登在資通訊技術（IT）與奈米電子領域處於領先地位，因此被譽為「矽薩克森」（Silicon Saxony）。此外，製藥、化妝品、機械工程與汽車製造也是其經濟支柱。\r\n\r\n交通門戶：身為重要交通樞紐，擁有三條高速公路、兩座遠程火車站、一個內河港口及德勒斯登機場。\r\n歷史沿革：從皇家官邸到現代首府\r\n建城歷史：考古發現可追溯至石器時代，文獻正式記載於 1206 年。它曾長期作為選帝侯及王室的居住地。\r\n行政變遷：1990 年兩德統一後再次成為薩克森自由邦的首府（在東德時期為行政區首府）。\r\n\r\n文化地標：易北河上的佛羅倫斯\r\n德勒斯登因其豐富的藝術收藏、巴洛克建築風格以及易北河谷的優美氣候，被譽為「易北河上的佛羅倫斯」（Elbflorenz）。\r\n著名建築：包括巴洛克風格的茨溫格宮（Zwinger）、聖母教堂（Frauenkirche）、森柏歌劇院（Semperoper）及德勒斯登王宮。\r\n博物館瑰寶：擁有「歷代大師畫廊」（Gemäldegalerie Alter Meister）與「綠穹珍寶館」（Grünes Gewölbe）。\r\n音樂傳統：曾是華格納、舒茲等大師的創作地，擁有著名的薩克森國家管弦樂團與十字架童聲合唱團。\r\n聖誕文化：創建於 1434 年的「聖誕果脯蛋糕市場」（Striezelmarkt）是德國歷史最悠久、最著名的聖誕市場之一。\r\n\r\n德勒斯登在二戰末期曾遭受毀滅性的轟炸，但今日的老城區已近乎完美地重建。','一、 起源與中世紀：易北河畔的斯拉夫定居點\r\n早期活動：早在西元前 5000 年（新石器時代），當地的 Nickern 已有大型環狀溝壑建築。\r\n名稱與建城：名稱源於古索布語 drežďany（意為「沼澤或河畔林居民」），顯示其最初為斯拉夫人的聚落。\r\n正式記載：1206 年首次見於文獻，1216 年正式被稱為「城市」（civitas）。1549 年，易北河兩岸的城區正式合併為一體。\r\n\r\n二、 近代早期：薩克森的心臟與巴洛克榮光\r\n皇家官邸：1485 年起成為韋廷王朝（Wettin）的永久居所。隨著薩克森升格為選侯國與王國，德勒斯登成為德意志重要的政治與文化中心。\r\n奧古斯特時代：在「強壯者」奧古斯特（August der Starke）統治下，德勒斯登因豐富的巴洛克建築與藝術收藏而享譽全球，奠定了其文化地位。\r\n戰爭與文化：雖然在七年戰爭中曾遭普魯士圍攻與炮擊，但也誕生了文化瑰寶——席勒（Friedrich Schiller）在此寫下《歡樂頌》（後成為歐盟盟歌）。\r\n\r\n三、 20 世紀的黑暗與毀滅\r\n納粹與迫害：納粹時期，德勒斯登約 5000 名猶太人遭到驅逐或屠殺（著名學者 Victor Klemperer 的日記詳細記錄了這段歷史）。1933 年，表現主義等「頹廢藝術」遭到查封與焚毀。\r\n二戰大轟炸：1945 年 2 月 13 日至 15 日，英美盟軍發動毀滅性空襲。市中心約 15 平方公里被完全摧毀，造成約 22,700 至 25,000 人死亡（曾被納粹與極右派誇大為 35 萬以進行宣傳）。\r\n\r\n四、 東德時期與兩德統一\r\n社會主義重建：東德時期（1952–1990），德勒斯登成為行政區首府。政府清除了大量老城遺跡，改建為社會主義風格建築（如普拉格大街）。\r\n重要重建工程：茨溫格宮、森柏歌劇院（1985 年完工）等標誌性建築在東德時期陸續修復。聖母教堂的廢墟則原封不動地保留，作為「反戰紀念」。\r\n和平革命：1989 年 10 月，德勒斯登爆發大規模示威，成立了「20 人小組」與當局對話，成為東德民主化進程的關鍵。\r\n\r\n五、 1990 年至今：重生與挑戰\r\n城市復興：兩德統一後，德勒斯登重新成為薩克森邦首府。2005 年，聖母教堂完成重建，被譽為「德勒斯登的奇蹟」。\r\n\r\n重大事件：\r\n2002 年世紀洪水：易北河水位創下 1845 年以來最高紀錄。\r\n科技發展：轉型為「矽薩克森」高科技中心。\r\n政治變遷：2014 年起，此地成為反移民運動 Pegida 的中心，引發社會關注。','https://api.lumoguide.com/storage/uploads/20260308/5WlxVBvoB1DuiAeFQNis.png','[\"https://api.lumoguide.com/storage/uploads/20260308/5WlxVBvoB1DuiAeFQNis.png\", \"https://api.lumoguide.com/storage/uploads/20260316/hYVzUf2ORSMnZSTFxyMK.png\", \"https://api.lumoguide.com/storage/uploads/20260316/ZICMIYCnrOHz9vLWXrrt.png\", \"https://api.lumoguide.com/storage/uploads/20260316/AGJTUCra80Eq0Ew4taeV.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-16 01:37:54','2026-03-16 05:06:02'),(27,25,3,3,'薩格勒布','Zegrab',2,17,47,NULL,'15.982900664907604','45.81308028267896',1,'歐元','克羅地亞語','81萬','斯拉夫人','薩格勒布 是克羅埃西亞的首都和最大城市。薩格勒布市本身也是一個縣。週邊地區構成獨立的薩格勒布縣，其行政中心也是薩格勒布市。薩格勒布是天主教大主教（薩格勒布總教區）、克羅埃西亞科學與藝術學院以及重要的行政和軍事機構所在地。作為商業和金融中心，薩格勒布具有國家級重要地位。','薩格勒布這個名字最早出現在 1094 年，當時匈牙利-克羅埃西亞的拉迪斯勞斯一世國王創立了薩格勒布教區。這座城市由東部的卡普托爾（主教城）和西部的格拉德茨（上城）兩個定居點發展而成。卡普托爾是神職人員的城市，自 11 世紀以來，薩格勒布主教區的主教和教士們就居住於此。商人和工匠們則定居在西邊鄰近山脊上的上城。兩個定居點之間的利益衝突不斷引發爭端。\r\n13 世紀，東南歐遭受了蒙古人部分毀滅性的征服。1235 年至 1270 年擔任克羅埃西亞和匈牙利國王的貝拉四世從格拉德茨組織了防禦。為感謝格拉德茨居民的支持，他於 1242 年授予他們《金印》，作為自由和獨立的象徵。 憑藉這份文件，格拉德茨成為自由王室城市，經濟繁榮時期就此展開。宮殿、教堂和防禦工事按照中歐和西歐的模式相繼建成。\r\n1557 年，薩格勒布首次被提及為克羅埃西亞的首都。該城市位於 1583 年為抵禦土耳其人而設立的軍事邊境的腹地。1669 年，耶穌會學院（Neoacademia Zagrabiensis）成立，這是 1874 年成立的薩格勒布大學的前身。\r\n後來，在兩座山間定居點的南部，下城（Donji grad）逐漸發展起來，最初圍繞著 17 世紀建造的、後來成為主要廣場的班·耶拉奇奇廣場（Ban-Jelačić-Platz）而發展。','https://api.lumoguide.com/storage/uploads/20251125/LjrMEWI5N5zId2pUv56r.png','[\"https://api.lumoguide.com/storage/uploads/20251125/LjrMEWI5N5zId2pUv56r.png\", \"https://api.lumoguide.com/storage/uploads/20260316/jzau6F23bfdqcdMgNM4B.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-16 03:55:55','2026-03-16 05:06:07'),(28,51,3,3,'蘇黎世','Zurich',2,29,28,NULL,'8.539136152177177','47.37903948336536',1,'瑞士法郎','英語/德語','約44萬','日耳曼','蘇黎世是瑞士的一座城市、政治市鎮，同時也是同名聯邦州（蘇黎世州）的首府。蘇黎世區與該市的行政範圍一致。\r\n\r\n截至 2024 年 12 月 31 日，蘇黎世市是瑞士最大的城市。周邊地區同樣人口稠密；城市建築和基礎設施在該市的東北部、西北部以及沿蘇黎世湖兩岸無縫延伸。蘇黎世城市群的核心區域（含市中心）居住著超過 100 萬人口，而整個城市群（截至 2022 年）約有 145 萬人，佔瑞士總人口的六分之一。\r\n\r\n該市位於瑞士高原東部，坐落於蘇黎世湖流出的利馬特河畔。其居民被稱為「蘇黎世人」（Zürcher），若要與州內其他地區居民區分時，則稱為「蘇黎世市民」（Stadtzürcher）。\r\n\r\n蘇黎世源於羅馬時期的定居點 Turicum，1262 年成為神聖羅馬帝國的自由直轄市，1351 年加入瑞士邦聯。在宗教改革家慈運理（Huldrych Zwingli）的帶領下，蘇黎世於 1519 年成為宗教改革中心（與維滕貝格、日內瓦和史特拉斯堡並列）。時至今日，它仍被視為全球歸正宗與重浸派的發源地。工業時代，蘇黎世崛起成為瑞士今日的經濟與金融中心，並發展為全球城市（Global City）。\r\n\r\n憑藉瑞士最大的火車站——蘇黎世火車總站，以及位於克洛滕（Kloten）市鎮境內的蘇黎世機場，蘇黎世成為了歐洲大陸的交通樞紐。由於坐擁多家跨國銀行（如瑞銀集團 UBS 與蘇黎世州銀行）及保險公司（如蘇黎世保險與瑞士再保險），蘇黎世是國際金融中心，也是瑞士最大的金融所在地，其後分別是日內瓦與盧加諾。此外，該市擁有蘇黎世聯邦理工學院（ETH Zürich）與蘇黎世大學這兩所瑞士規模最大的高等學府。儘管人口數量相對較少，蘇黎世仍被列入世界大都市之列，是瑞士媒體與創意產業最重要的中心。憑藉其蘇黎世湖畔的地理位置、保存完好的中世紀老城區、多元的文化活動及夜生活，它同時也是一座旅遊重心。\r\n\r\n多年來，蘇黎世與巴塞爾、日內瓦並列為全球生活品質最高的城市之一，但同時也與日內瓦並列為全球生活成本最高的城市。蘇黎世是全球百萬富翁密度第三高的城市，僅次於摩納哥與日內瓦。','一、 早期歷史與中世紀（建立至宗教改革前）\r\n\r\n城市崛起： 不同於瑞士其他大城，蘇黎世直到中世紀早期才晉升為城市。其前身為凱爾特人的聚落及羅馬時期的海關站（Turīcum）。\r\n\r\n教會影響： 早期城市發展與**大教堂（Grossmünster）及聖母大教堂（Fraumünster）**兩大修道院緊密相關。聖母大教堂的女修道院院長曾是名義上的城市領主。\r\n\r\n走向自治： 1218 年蘇黎世獲得「帝國直轄權」，並在 15 世紀正式成為擁有高度自治權的「帝國自由城市」。\r\n\r\n加入聯邦： 1351 年為了抵禦哈布斯堡王朝的擴張，蘇黎世加入瑞士邦聯，並與伯恩共同成為該聯盟的主導城市。\r\n\r\n二、 宗教改革：轉折與繁榮\r\n\r\n改革中心： 1519 年在**慈運理（Huldrych Zwingli）**領導入，蘇黎世成為宗教改革的重要基地，被稱為「利馬特河畔的羅馬」。\r\n\r\n文化貢獻： 誕生了最早的德語聖經之一（蘇黎世聖經），同時也是重浸派運動的發源地。\r\n\r\n經濟助益： 宗教改革後吸引了大量來自義大利和法國的難民，他們帶來的新技術（如紡織業）極大地促進了蘇黎世的經濟繁榮。\r\n\r\n三、 18 與 19 世紀：現代化的轉型\r\n\r\n身分轉變： 1798 年法國入侵後，蘇黎世由獨立共和國轉變為蘇黎世州的首府。\r\n\r\n經濟騰飛： 19 世紀由**阿爾弗雷德·埃舍爾（Alfred Escher）**等自由派領導，蘇黎世從紡織業中心轉型為銀行與保險業林立的金融重鎮。\r\n\r\n交通與基礎建設： 1847 年瑞士第一條鐵路開通；1893 年落成的總火車站使其成為歐洲交通樞紐。\r\n\r\n城市擴張： 1892 年進行了第一次大規模市鎮合併，人口激增至 12 萬，成為瑞士第一個大都市。\r\n\r\n四、 20 世紀：政治、戰爭與建設\r\n\r\n「紅色蘇黎世」： 20 世紀初是工人運動的高峰，1928 年社民黨（SP）執政，積極推動社會住房建設。\r\n\r\n二次擴張： 1934 年第二次市鎮合併，人口突破 31 萬。\r\n\r\n戰爭與定位： 二戰前夕的「國家博覽會」成為瑞士抵抗納粹德國的精神象徵。戰後，1946 年邱吉爾在此發表著名的「讓歐洲崛起」演說；同年，克洛滕（Kloten）國際機場獲批建設。\r\n\r\n社會變革： 1960-1980 年代經歷了強烈的青年抗議運動（如 Globus 暴動）；1966 年蘇黎世市公民投票通過了女性投票權。\r\n\r\n交通爭議： 曾多次計畫興建地鐵（U-Bahn），但均被公民投票否決，導致其至今仍以完善的路面電車與通勤鐵路（S-Bahn）為主。','https://api.lumoguide.com/storage/uploads/20260301/fYvDtj3QMmET0nJ0Et8m.png','[\"https://api.lumoguide.com/storage/uploads/20260301/fYvDtj3QMmET0nJ0Et8m.png\", \"https://api.lumoguide.com/storage/uploads/20260317/b9GSczFAbuRGPnvqDMeS.png\", \"https://api.lumoguide.com/storage/uploads/20260317/o5JVRzfkL0xi7OOa2Mdo.png\", \"https://api.lumoguide.com/storage/uploads/20260317/30sIrfWhhTfBUSG7nhg6.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-17 06:08:14','2026-03-18 00:25:33'),(29,127,3,3,'皮蘭','Piran',2,17,46,NULL,'13.563733638623587','45.530668900070985',0,'EUR','斯洛維尼亞語/義大利語','3733','斯拉夫','? 斯洛維尼亞的度假勝地\r\n地理位置： 位於斯洛維尼亞西南部的皮蘭灣（Gulf of Piran），濱臨亞德里亞海。\r\n地區地位： 它是**斯洛維尼亞伊斯特里亞（Slovenian Istria）**地區的三大主要城鎮之一。\r\n雙語特質： 作為一座雙語城市，居民普遍使用斯洛維尼亞語與義大利語。\r\n建築風格： 以其中世紀建築聞名，擁有獨特的狹窄街道與緊湊密集的房舍景觀。\r\n行政與旅遊： 它是**皮蘭區（Municipality of Piran）**的行政所在地，也是斯洛維尼亞最頂尖的旅遊景點之一。','1. 早期歷史與城鎮起源\r\n前羅馬時期： 由伊利里亞的 Histri 部落居住，他們是農夫、獵人，也是干擾羅馬貿易的海盜。\r\n羅馬與拜占庭： 西元前 178-177 年併入羅馬帝國。6 世紀末因阿瓦爾人與斯拉夫人入侵，居民退縮至易守難攻的半島，開啟了城市化。7 世紀在拜占庭統治下成為防禦重鎮。\r\n名稱由來： 可能源自希臘語 pyrrhos（紅，因當地的紅飛砂岩）或 pyros（火，因古老的燈塔）。\r\n\r\n2. 威尼斯與奧地利時期\r\n威尼斯共和國（1283–1797）： 長達 500 年的統治賦予了皮蘭豐富的建築與文化。1558 年曾爆發大瘟疫，奪走三分之二的人口。\r\n奧匈帝國時期： 19 世紀末至 20 世紀初，皮蘭人口一度超過 15,000 人。\r\n族群比例： 當時約 80% 為義大利裔，約 15% 為斯洛維尼亞裔。\r\n交通先驅： 1909 年開通了巴爾幹半島第一條無軌電車線。\r\n\r\n3. 二戰後的族群大遷徙（Istrian Exodus）\r\n政權更迭： 一戰後歸義大利；二戰後（1954年）正式併入南斯拉夫。\r\n人口與語言翻轉： * 在「伊斯特里亞－達爾馬提亞大流亡」期間，大量義大利裔居民選擇離開南斯拉夫移居義大利或海外。\r\n20 世紀中葉以前： 義大利語是主導語言。\r\n併入南斯拉夫後： 斯洛維尼亞語取代義大利語成為主要語言。','https://api.lumoguide.com/storage/uploads/20260318/m2es5dfAoqaD5usi1LFY.png','[\"https://api.lumoguide.com/storage/uploads/20260318/m2es5dfAoqaD5usi1LFY.png\", \"https://api.lumoguide.com/storage/uploads/20260319/owtR08HEARp2Jb1uALSr.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-19 00:03:19','2026-03-19 00:20:51'),(30,111,3,3,'薩拉熱窩','Sarajevo',2,17,48,NULL,'18.417664091322454','43.85459031679607',1,'波黑馬克BAM','波斯尼亞語','約27.6萬','波斯尼亞','薩拉熱窩（Sarajevo）重點摘要\r\n薩拉熱窩是波士尼亞與赫塞哥維納的首都與最大城市，其行政區內人口約 27.5 萬，包含周邊地區的薩拉熱窩州則有約 41.3 萬居民。它坐落於巴爾幹半島核心的薩拉熱窩山谷，四周環繞著迪納拉阿爾卑斯山，米里雅茨河（Miljacka）蜿蜒穿過市中心。\r\n\r\n1. 地位與「歐洲的耶路撒冷」\r\n薩拉熱窩是該國的政治、金融、文化中心。因其悠久的歷史與濃厚的多元文化，薩拉熱窩常被稱為「歐洲的耶路撒冷」或「巴爾幹的耶路撒冷」，是歐洲少數能在同一街區同時並存清真寺、天主教堂、東正教堂與猶太會堂的城市。\r\n\r\n2. 三個關鍵歷史時刻\r\n第一次世界大戰的導火線（1914）： 奧匈帝國皇儲斐迪南大公在此被加夫里洛·普林西普暗殺，直接引爆了第一次世界大戰，終結了奧匈帝國在當地的統治。\r\n奧運繁榮期（1984）： 薩拉熱窩成功舉辦了 1984 年冬季奧運會，那是該市歷史上繁榮且充滿希望的時代。\r\n現代史上最長的圍城（1992–1996）： 在波士尼亞戰爭期間，薩拉熱窩遭受了長達 1,425 天的圍困，這是現代史上對首都城市最長久的圍攻。\r\n\r\n3. 當代榮譽與文化\r\n文化創意之都： 薩拉熱窩是聯合國教科文組織（UNESCO）認定的「創意城市」與「電影之都」。\r\n旅遊新亮點： 憑藉其文化魅力，薩拉熱窩屢獲旅遊大獎肯定。2024 年 10 月，《國家地理》雜誌的讀者更是將薩拉熱窩票選為 2025 年全球最佳旅遊目的地。\r\n\r\n薩拉熱窩是一座從慘烈圍城中浴火重生、韌性極強的城市，如今已轉型為巴爾幹地區最具活力與文藝氣息的旅遊重鎮。','1. 史前與古典時期\r\n早期定居： 新石器時代的「布特米爾文化」（Butmir culture）在今日薩拉熱窩近郊留下了獨特的陶器遺存。\r\n羅馬時代： 公元 9 年，羅馬帝國征服了當地的伊利里亞部落（Daesitiates），隨後在伊利扎（Ilidža）地區建立了名為 Aquae Sulphurae 的殖民地。\r\n\r\n2. 中世紀與鄂圖曼帝國（1461–1878）\r\n建城： 1461 年，鄂圖曼帝國首任波士尼亞總督伊薩-貝格（Isa-Beg Ishaković）將此處轉型為城市，因總督府（Saray）的存在而得名。\r\n繁榮中心： 薩拉熱窩發展為鄂圖曼在巴爾幹僅次於伊斯坦堡的第二大城。16 世紀在加齊·胡斯列夫貝格（Gazi Husrev-beg）的管理下，建築了大批清真寺與集市（Baščaršija）。\r\n災難與衰退： 1697 年，歐根親王率軍劫掠並焚毀全城，城市元氣大傷，人口從巔峰時期的 8 萬人（1660 年）逐漸萎縮。\r\n\r\n3. 奧匈帝國與兩次世界大戰（1878–1945）\r\n歐化轉型： 1878 年奧匈帝國接管後，薩拉熱窩經歷了大規模的都市現代化（如鋪設歐洲第一座電車）。市容呈現鄂圖曼傳統市場與西方「新藝術運動」（Secession）風格的獨特融合。\r\n一戰引爆點： 1914 年 6 月 28 日，奧匈皇儲斐迪南大公在此被加夫里洛·普林西普暗殺，直接引發了一戰。\r\n二戰浩劫： 二戰期間薩拉熱窩併入傀儡政權「克羅埃西亞獨立國」（NDH），城內龐大的猶太社群遭到納粹與烏斯塔沙（Ustaše）慘無人道的種族滅絕，近 85% 的波士尼亞猶太人遇難。\r\n\r\n4. 南斯拉夫時期（1945–1992）\r\n工業與繁榮： 戰後作為南斯拉夫社會主義聯邦下波赫共和國的首都，城市經歷快速工業化與住宅區擴建。人口從 1945 年的 11.5 萬激增至 1990 年代的約 60 萬。\r\n奧運榮光： 1984 年舉辦冬季奧運會，是這座城市在南斯拉夫時期最繁榮、最具國際能見度的時刻。\r\n\r\n5. 薩拉熱窩圍城與戰後（1992–至今）\r\n現代史上最長圍城： 波士尼亞戰爭期間（1992–1996），塞爾維亞軍隊從周邊高地將薩拉熱窩圍困長達 1,425 天。\r\n慘痛犧牲： 圍城期間約有 11,541 人（含 1,500 多名兒童）犧牲，超過 56,000 人受傷。城內留下的迫擊砲彈坑被填上紅樹脂，稱為「薩拉熱窩玫瑰」。\r\n人口結構變遷： 戰爭結束後，根據代頓協議（Dayton Agreement），大量塞爾維亞裔居民離開了薩拉熱窩，使得這座原本高度多元的城市在戰後人口結構變得較為單一。\r\n現代面貌： 戰後透過國際援助大規模重建，地標性建築如薩拉熱窩纜車（Trebević cable car）重啟，並再度定位為國際旅遊與創意之都。','https://api.lumoguide.com/storage/uploads/20260314/LcolTq80zrrXcO8ACDmO.png','[\"https://api.lumoguide.com/storage/uploads/20260314/LcolTq80zrrXcO8ACDmO.png\", \"https://api.lumoguide.com/storage/uploads/20260319/M4IP3oAmtNEMiWYjQeLO.png\", \"https://api.lumoguide.com/storage/uploads/20260319/t10VMLjnCt1zc49e40hQ.png\", \"https://api.lumoguide.com/storage/uploads/20260319/VjqTFcBX7CnwGy48sWNn.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-19 00:05:09','2026-03-19 00:20:59'),(31,133,3,3,'羅卡馬杜爾','Rocamadour',2,7,23,NULL,'1.6216076261944923','44.800460697223286',0,'EUR','法語','法蘭西','597','? 地理位置與地位\r\n位置： 位於法國西南部洛特省（Lot），屬於舊時的凱爾西（Quercy）行省。\r\n殊榮： 該村莊是「法國最美村莊」（Les Plus Beaux Villages de France）協會的成員。\r\n\r\n⛪ 歷史與宗教聖地\r\n景觀特點： 以其坐落在多爾多涅河（Dordogne）支流上方的峽谷懸崖壯麗景色聞名。\r\n聖母朝聖地： 自 12 世紀以來，這裡的聖母聖殿吸引了來自各國的朝聖者。\r\n著名朝聖者： 歷史上多位顯赫人物曾造訪於此，包括英王亨利二世、法國國王路易九世（聖路易）、卡斯提亞的布蘭卡，以及聖多明尼克和聖伯納德。\r\n\r\n? 城鎮與特產\r\n觀光與經濟： 修道院建築群與朝聖教堂下方的城鎮，早期依賴朝聖者維生，如今則是繁忙的旅遊中心。\r\n名產： 當地著名的**羅卡馬杜山羊起司（Rocamadour cheese）**於 1996 年獲得法國原產地命名控制（AOC）認證。','? 史前時期\r\n早期居住： 舊石器時代的洞穴壁畫（如 Grotte des Merveilles）證明此地已有居民。青銅時代時，Linarscave 洞穴曾作為地下墓地與居所。\r\n鐵人時代： 西元前 8 世紀，來自德國中部的 Cadurques 族人攜帶鐵製武器殖民此地。當地的山城（Oppidum）遺跡可能與高盧戰爭期間對抗羅馬軍隊有關。\r\n\r\n? 中世紀：興起與鼎盛\r\n社會階層： 村莊的三層結構反映了中世紀社會：最上方是騎士，中間是神職人員，下方靠近河流處則是平民勞工。\r\n朝聖起源： 1105 年在懸崖避風處建造了一座小禮拜堂。1148 年宣佈發生首個神蹟後，開始吸引聖母朝聖者。\r\n黑聖母與建築： 12 世紀著名的《神蹟之書》（Livre des Miracles）記載了其名聲。1159 年英王亨利二世前來謝恩。現存的黑聖母像及主要宗教建築均建於此世紀。\r\n聖阿馬杜（Saint Amadour）： 1166 年在禮拜堂入口發現具完整遺體，被視為聖阿馬杜。相傳他與耶穌關係親近，羅卡馬杜因此找到了自己的聖人。\r\n\r\n? 衰落與破壞\r\n天災與瘟疫： 14 世紀受氣候變冷、饑荒與黑死病侵襲，修道士撤離，由主教委任的教士管理。\r\n宗教戰爭： 1562 年新教僱傭兵大舉破壞，焚毀並掠奪了自 12 世紀以來的雕像、繪畫與珠寶。聖阿馬杜的遺體亦被毀壞（新教隊長 Jean Bessonia 用鐵鎚將其擊碎）。\r\n法國大革命： 該遺址在革命期間再次遭到洗劫。\r\n\r\n? 現代的羅卡馬杜\r\n旅遊轉型： 20 世紀初以來，這裡已轉變為以旅遊為主的勝地，但朝聖活動依然重要。\r\n多元活動： 周邊設有老鷹岩（鳥類公園）與猴子森林，並舉辦年度起司節。戶外活動與熱氣球也非常受歡迎。\r\n精神吸引力： 懸崖建築與黑聖母像不僅吸引天主教徒，也因其「神秘能量」與前基督教起源的傳說，吸引了許多 New Age（新時代） 信仰者。','https://api.lumoguide.com/storage/uploads/20260319/l57BRsIPsUfEr93Q6MZj.png','[\"https://api.lumoguide.com/storage/uploads/20260319/l57BRsIPsUfEr93Q6MZj.png\", \"https://api.lumoguide.com/storage/uploads/20260319/jQAjpuMlte5hJZqObwpu.png\", \"https://api.lumoguide.com/storage/uploads/20260319/9pD2zW7tjCmpeqF5H3WQ.png\", \"https://api.lumoguide.com/storage/uploads/20260319/1QNHY7wcOH7dgggPu1wa.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-19 00:20:27','2026-03-19 00:20:43'),(32,135,3,3,'日內瓦','Geneva',2,29,28,NULL,'6.149175352828027','46.210133296625216',1,'瑞士法郎','法語/英語','約21萬','法蘭西','【城市概況與地位】\r\n日內瓦（Geneva，/dʒɪˈniːvə/；法語：Genève [ʒ(ə)nɛv]）是瑞士人口第二多的城市，也是法語區（羅曼地，Romandy）人口最稠密的城市。該市位於瑞士西南部，處於隆河（Rhône）流出萊芒湖（日內瓦湖）的交匯點，是日內瓦共和國與州（Republic and Canton of Geneva）的首府。日內瓦是一座全球化城市、國際金融中心，更是全球外交中心，因此被譽為「和平之都」。\r\n\r\n【國際組織與外交】\r\n日內瓦擁有全球數量最多的國際組織，其中包括聯合國眾多機構的總部，以及紅十字會的紅十字國際委員會（ICRC）與紅十字會與紅新月會國際聯合會（IFRC）。這裡不僅是關於戰爭人道待遇的《日內瓦公約》簽署地，在第一次世界大戰後，更曾是**國際聯盟（League of Nations）**的所在地。日內瓦與紐約、波昂、巴塞爾及史特拉斯堡等城市齊名，擁有一項獨特的地位：儘管並非國家首都，卻是至少一個關鍵國際組織的總部所在地。\r\n\r\n【人口與大都會區】\r\n截至 2021 年 1 月，日內瓦市（Ville de Genève）在其 16 平方公里的市轄領土內擁有 203,856 名居民。根據歐盟統計局（Eurostat）的官方定義，日內瓦大都會區（含沃州郊區及法國安省與上薩伏依省的外圍城鎮）面積達 2,292 平方公里，2021 年人口為 1,053,436 人。由日內瓦州、尼翁區（Nyon District）及法國境內的「法屬日內瓦大都會極」（由 8 個法國跨市鎮委員會組成）共同構成了**「大日內瓦」（Grand Genève）**。這是一個負責統籌跨境大都會區合作的「地方跨國合作組織」（GLCT），其涵蓋範圍為 1,996 平方公里，人口達 1,046,168 人，其中 58.3% 居住在瑞士，41.7% 居住在法國。\r\n\r\n【經濟與宜居排名】\r\n在 2025 年的全球金融中心指數（GFCI）中，日內瓦被評為全球第 15 大金融中心，在歐洲排名第 4，僅次於倫敦、法蘭克福和都柏林。2024 年，日內瓦被美世（Mercer）評為全球第 3 大宜居城市，同時也是全球生活成本第 4 高的城市。此外，在 2018 年瑞銀集團（UBS）的全球城市排名中，日內瓦在總薪資收入方面排名第一，購買力排名第四，且當時為全球生活費第二貴的城市。','1. 起源與中世紀（西元前 58 年 – 15 世紀）\r\n軍事要塞： 凱撒在《高盧戰記》中首次記載此地。地名語源可能指「河口」或「膝蓋狀彎角」。\r\n權力交織： 長期作為主教駐地，隨後歸屬神聖羅馬帝國。1162 年獲得帝國直轄權，成為具備會展規模的商業重鎮。\r\n\r\n2. 宗教改革與獨立共和（16 – 18 世紀）\r\n新教羅馬： 1536 年在法雷爾影響下推行改革，宣告成立日內瓦共和國。加爾文於 1559 年創辦學院（今日內瓦大學）。\r\n難民紅利： 法國胡格諾派等難民湧入，帶來了先進的鐘錶工藝與絲綢貿易，奠定產業基礎。\r\n啟蒙與衝突： 18 世紀頻發社會運動（如盧梭事件），爭取經濟與公民權利。\r\n\r\n3. 加入聯邦與工業發展（19 世紀）\r\n正式入瑞： 經歷拿破崙併吞後，於 1815 年正式成為瑞士第 22 個州。\r\n人道與政治： 1864 年成為紅十字國際委員會所在地；同年主辦第一國際大會，推動勞工權益。\r\n基礎建設： 拆除城牆、興建大劇院（1879 年）；建設動力工廠調節湖水並供應工業能源。\r\n\r\n4. 20 世紀至今：國際之都與社會挑戰\r\n外交中心： 1920 年成為國際聯盟（國聯）總部，隨後舉辦多場決定世界格局的國際會議（如 1954 印度支那會議）。\r\n社會陰影： 1932 年發生士兵鎮壓示威的「血腥之夜」。\r\n當前議題： 被評為「歐洲改革之城」。目前面臨極高房價、外交官特權（豁免權）以及與法國跨境通勤者之間的資源與公平性爭議。','https://api.lumoguide.com/storage/uploads/20260320/B0PqyBhsx27cRpyWjDxb.png','[\"https://api.lumoguide.com/storage/uploads/20260320/B0PqyBhsx27cRpyWjDxb.png\", \"https://api.lumoguide.com/storage/uploads/20260320/L6sbeJ5Mg0GKof4PurJZ.png\", \"https://api.lumoguide.com/storage/uploads/20260320/wUjwgkaKukxYhzMJmEBv.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-20 01:36:00','2026-03-20 01:40:44'),(33,52,3,3,'盧塞恩','Lucerne',2,29,28,NULL,'8.311756666636965','47.05149507150196',0,'CHF','英語/德語','8.3萬','日耳曼','琉森（Lucerne，德語：Luzern）是瑞士中部的一座城市及市鎮，位於該國的德語區。琉森是琉森邦（Canton of Lucerne）的首府，隸屬於同名區。琉森擁有約 82,000 人口，是瑞士中部人口最多的城市，同時也是該地區經濟、交通、文化與媒體的中心。其城市都會區由 19 個市鎮組成，總人口約 220,000 人。\r\n\r\n由於坐落在琉森湖（德語：Vierwaldstättersee）湖畔及其流出的羅伊斯河（Reuss）河口，且能遠眺瑞士阿爾卑斯山脈中的皮拉圖斯峰（Pilatus）與瑞吉峰（Rigi），琉森長期以來一直是著名的旅遊勝地。這座城市的標誌性建築之一是卡貝爾橋（德語：Kapellbrücke，又稱教堂橋），這是一座始建於 14 世紀的木結構橋樑。\r\n\r\n琉森的官方語言是德語，但當地主要的口語是阿勒曼尼語系（Alemannic）的瑞士德語變體——琉森德語。','早期歷史與建城（750–1386）\r\n6 世紀羅馬帝國崩潰後，日耳曼阿勒曼尼人（Alemannic）加強了對今日瑞士境內該地區的影響力。\r\n約 750 年，本篤會聖萊奧德加爾修道院（St. Leodegar）建立，後來在 9 世紀中葉被阿爾薩斯的穆爾巴赫修道院（Murbach Abbey）收購；此時該地區已以「Luciaria」之名為人所知。\r\n該地名的起源尚無定論，可能源自拉丁語中「狗魚」（pike）一詞 lucius，意指羅伊斯河（Reuss）中的捕魚點。也有人提出它源自神名「Lugus」，但在語音學上難以成立。無論如何，該名稱很早就因大眾詞源學而與拉丁語的「燈籠」（lucerna）產生了聯想。\r\n1178 年，琉森脫離穆爾巴赫修道院的管轄而獨立，該市的建立可能就在同年。作為通往哥達貿易路線（Gotthard trade route）上具戰略意義的門戶，琉森的重要性日益增長。\r\n至 1290 年，琉森已成為一座擁有約 3,000 名居民、自給自足的中型城市。當時，魯道夫一世國王（King Rudolph I von Habsburg）取得了對聖萊奧德加爾修道院及其領地（包括琉森）的管轄權。民眾對日益增長的哈布斯堡家族勢力感到不滿，於是琉森與鄰近城鎮結盟以尋求獨立。1332 年 11 月 7 日，琉森與烏里（Uri）、施維茨（Schwyz）和下瓦爾登（Unterwalden）這三個森林州共同組成了「永恆的」瑞士邦聯（Eidgenossenschaft）。\r\n此後，蘇黎世、楚格和伯恩等城市加入聯盟。隨著這些成員的加入，奧地利在該地區的統治宣告結束。1386 年，琉森在森帕赫戰役（Battle of Sempach）中戰勝哈布斯堡家族，解決了爭端。對琉森而言，這場勝利開啟了一個擴張時代。此後不久，該市自行授予了許多此前被哈布斯堡家族扣留的權利。至此，琉森的邊界已大致等同於今日（不含利陶/Littau）。\r\n\r\n從城市到城邦（1386–1520）\r\n1415 年，琉森獲得了西吉斯蒙德皇帝頒發的「帝國自由權」（Reichsfreiheit），成為瑞士邦聯中強大的一員。該市發展基礎設施、增加稅收並任命當地的官員。約 1350 年前後，由於黑死病與多場戰爭，該市人口從 3,000 人下降了約 40%。\r\n1419 年的城鎮記錄顯示了首宗針對男性的女巫審判。\r\n1471 年，通過了迫害印度裔羅姆人（Romani people）的法律。\r\n\r\n瑞士天主教城鎮（1520–1798）\r\n在邦聯中日益成長的城鎮中，琉森吸引新居民的能力尤為突出。琉森保持著以天主教為主的信仰，並從 1453 年到 1616 年舉辦自己的年度「受難劇」（passion play），該劇為期兩天，每天演出長達 12 小時。隨著宗教改革導致邦聯分裂，1520 年後，大多數鄰近城市轉向新教，但琉森保持天主教信仰。1531 年天主教徒在卡佩爾戰役（Battle at Kappel）中擊敗新教徒後，天主教城鎮主導了邦聯。正是在此期間，耶穌會士於 1567 年首次來到琉森，他們的到來得到了米蘭總主教卡洛·博羅梅奧樞機（Cardinal Carlo Borromeo）的大力支持。然而，該地區最終仍由蘇黎世、伯恩和巴塞爾等新教城市主導，這些城市在 1712 年的托根堡戰爭（Toggenburg War）中擊敗了天主教勢力。琉森在邦聯中原有的顯赫地位從此喪失。在 16 和 17 世紀，戰爭和流行病逐漸減少，導致該國人口強勁增長。\r\n1653 年的瑞士農民戰爭中，琉森遭到農民軍圍困，隨後迅速與叛軍簽訂了和平條約。\r\n\r\n革命世紀（1798–1914）\r\n1798 年，法國大革命開始九年後，法國軍隊進入瑞士。舊瑞士邦聯崩潰，政府轉向民主。工業革命在琉森發生得較晚，到 1860 年，僅有 1.7% 的人口從事工業，大約僅為當時全國平均水平的四分之一。農業是該邦主要的經濟產出，僱用了約 40% 的勞動力。儘管如此，工業仍從琉森周邊地區被吸引到該市。從 1850 年到 1913 年，人口翻了四倍，移民潮增加。1856 年，火車首次將該市與奧爾滕（Olten）和巴塞爾連接起來，隨後於 1864 年連接至楚格和蘇黎世，最後於 1897 年通往南方。\r\n弗里德里希·席勒（Friedrich Schiller）1804 年的劇作《威廉·泰爾》（William Tell）極大地提升了琉森及其周邊地區的聲譽。席勒本人未曾到過琉森，但他受到了妻子洛特（Lotte）和好友約翰·沃爾夫岡·馮·歌德（Johann Wolfgang von Goethe）的啟發，這兩人皆曾親自造訪過該市及其周邊的邦。歌德在 1779 年前往義大利途中曾下榻於赫希森廣場（Hirschenplatz）。\r\n在 19 世紀後期，琉森成為藝術家、王室成員及其他人避暑勝地的熱門目的地。德國作曲家理察·華格納（Richard Wagner）於 1866 年在特里布申（Tribschen）建立住所，並在此生活和工作。隨後，維多利亞女王（Queen Victoria）於 1868 年造訪該市，使其聲名大噪；期間她參觀了卡貝爾橋和獅子紀念碑，並饒有興致地用母語德語與當地人交談。\r\n美國作家馬克·吐溫（Mark Twain）在 1878 年和 1897 年兩次造訪後，於其遊記中進一步推廣了這座城市及其周邊地區。1892 年，瑞士詩人兼未來諾貝爾獎得主卡爾·施皮特勒（Carl Spitteler）也在琉森定居，直到 1924 年去世。\r\n琉森作為時尚旅遊目的地的地位，使其成為現代旅遊業最早的中心之一。該市一些最著名的建築皆為此時期的酒店，例如施威霍夫酒店（Schweizerhof Hotel，1845 年）、國家大酒店（Grand Hotel National，1870 年）和古奇城堡酒店（Château Gütsch，1879 年）。瑞士酒店經營者凱撒·里茲（César Ritz）於 1878 年至 1888 年間在國家大酒店擔任經理。\r\n\r\n1993 年大火\r\n1993 年 8 月，市中心的卡貝爾橋遭遇一場大火，內部三分之二的畫作被毀。隨後大橋進行了重建，並於 1994 年 4 月重新對公眾開放，總維修費用為 340 萬瑞士法郎。\r\n\r\n與利陶（Littau）合併\r\n2007 年 6 月 17 日，琉森市和鄰近的利陶（Littau）鎮選民在全民公投中同意合併。該決議於 2010 年 1 月 1 日生效。新城市仍稱為琉森，人口約 8 萬，成為瑞士第七大城市。根據一項研究結果，此次公投的結果預計將為與其他鄰近城市和城鎮進行談判，以創建一個統一的「城市區域」鋪平道路。','https://api.lumoguide.com/storage/uploads/20260302/3mWBNwQ0J43rXIwHWGIp.png','[\"https://api.lumoguide.com/storage/uploads/20260302/3mWBNwQ0J43rXIwHWGIp.png\", \"https://api.lumoguide.com/storage/uploads/20260302/wG2ww4EE5XfCY5JnbL7j.png\", \"https://api.lumoguide.com/storage/uploads/20260320/PyaE1XuTq0pjTN2mfdLT.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-20 01:59:32','2026-03-20 02:00:36'),(34,50,3,3,'因斯布魯克','Innsbruck',2,29,20,NULL,'11.389930861513456','47.2702066363858',0,'歐元','德語','約13.2萬','日耳曼','因斯布魯克（Innsbruck，當地奧地利-巴伐利亞方言發音為 Innschbrugg）是奧地利西部的一座大城市，也是提洛邦（Tirol）的首府。這座曾作為提洛伯爵領地古都的城市，其標誌性建築是「黃金屋頂」（Goldenes Dachl）。\r\n\r\n截至 2025 年 1 月 1 日，因斯布魯克擁有 132,499 名居民，是提洛邦人口最多的城市，同時也是奧地利第五大城市（僅次於維也納、格拉茲、林茲和薩爾斯堡）。在其都會區內約生活著 300,000 人。此外，約有 30,000 名就讀於因斯布魯克大學、因斯布魯克醫學大學的學生及其他人員在此設立第二居所；','因斯布魯克歷史精要\r\n\r\n1. 早期起源與羅馬時期\r\n史前定居：定居史可追溯至新石器時代，因斯布魯克盆地已連續有人居住超過 3000 年。\r\n羅馬要塞：公元前 15 年，羅馬人為保護交通要道建立軍事站 Veldidena（現威爾滕區），直到公元 600 年左右被毀。\r\n\r\n2. 中世紀：城市的誕生與崛起\r\n命名與權利：1180 年安代克斯伯爵建立貿易據點，1187 年獲得市場權，拉丁語名 Oeni Pons 即意為**「因河上的橋」**。\r\n哈布斯堡統治：1363 年歸屬奧地利哈布斯堡家族。\r\n\r\n首府輝煌：1420 年成為領地首府。「空口袋」腓特烈四世與馬克西米利安一世時期最為繁榮，留下了黃金屋頂、霍夫堡皇宮等著名建築。\r\n\r\n3. 近代早期與動盪\r\n學術中心：1562 年成立全奧地利最古老的中學；1669 年正式創立因斯布魯克大學。\r\n戰爭衝突：19 世紀初曾被拿破崙轉交給巴伐利亞統治 8 年，期間爆發了著名的提洛民族起義（1809 年）。1849 年正式成為提洛邦首府。\r\n\r\n4. 20 世紀：奧運與現代發展\r\n二戰陰影：1938 年遭納粹德國併吞，戰爭期間遭受 22 次空襲，1945 年由美軍接管。\r\n奧運之城：曾舉辦過兩屆冬季奧運會（1964、1976）及首屆冬季青奧會（2012），是享譽國際的冬運中心。\r\n政治活動：20 世紀中葉曾是推動「南提洛」回歸奧地利運動的重要基地。\r\n\r\n5. 21 世紀現狀\r\n醫學與運動：醫學院於 2004 年獨立為醫學大學。近年持續舉辦如世界單板滑雪賽（Air & Style）、歐洲足球錦標賽（2008）及世界公路自由車賽（2018）等大型賽事。','https://api.lumoguide.com/storage/uploads/20260301/ZY6ArMeIFIcqHj8Wd3Ra.png','[\"https://api.lumoguide.com/storage/uploads/20260301/ZY6ArMeIFIcqHj8Wd3Ra.png\", \"https://api.lumoguide.com/storage/uploads/20260301/mVKFumPnFmq7Sf8ol7le.png\", \"https://api.lumoguide.com/storage/uploads/20260301/Tw1psmfAeDOCXDe3Gc5E.png\", \"https://api.lumoguide.com/storage/uploads/20260321/TCL6ldsKp1BzJwDB9nHA.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-21 04:19:03','2026-03-21 04:44:52'),(35,18,3,3,'哈爾斯塔特','Hallstatt',2,29,20,NULL,'13.65045276267163','47.564796619772224',0,'歐元','德語','約800','日耳曼','哈爾施塔特（Hallstatt），也稱為哈爾施塔特湖畔哈爾施塔特（Hallstatt am Hallstätter See），是奧地利上奧地利州薩爾茨卡默古特地區的一座集鎮，位於哈爾施塔特湖畔，人口737人（截至2025年1月1日）。它與達赫斯坦山脈和內薩爾茨卡默古特地區共同構成了聯合國教科文組織世界遺產哈爾施塔特-達赫斯坦/薩爾茨卡默古特。根據在城鎮上方一處大型墓地發現的文物，早期鐵器時代（公元前800年至公元前450年）的一段時期被稱為哈爾施塔特時期。','這片環境惡劣、山巒疊嶂的地區，居住條件艱苦，但早在新石器時代就可能有人活動。這得歸功於這裡豐富的天然鹽礦，數千年來一直有人開採。最古老的發現（例如，一件新石器時代早期的鞋楦石斧）可以追溯到公元前5000年左右。然而，這種被稱為「雷霆」的石器工具在中世紀和近代早期也廣泛流通。 1846年，約翰·格奧爾格·拉姆紹爾在薩爾斯堡山的高處發現了一處墓地。最早的鐵器鍛造廠之一也在此被發掘。繁榮的貿易和由此帶來的繁榮促進了一種高度發展的文化的形成，這種文化因在薩爾斯堡山谷的發現而被命名為哈爾施塔特文化。該文化大約從公元前800年延續到公元前400年，並使薩爾斯堡這個地方聞名於世。\r\n\r\n早期中世紀沒有文字記載，考古證據也無法證實哈施塔特曾經有持續的定居歷史。 1311年，哈爾施塔特被授予市場權，這標誌著其經濟地位的重要性。該鎮的名字源自於鹽場，是典型的「霍爾」地名。\r\n\r\n自1607年以來，一條重力輸鹽管道一直向北輸送鹽水至特勞恩湖畔埃本塞的鹽場，那裡有更豐富的柴火資源。這條工業管道是世界上仍在使用的最古老的管道，最初由掏空的針葉樹幹建造，現在則由鐵和塑膠製成。它橫跨戈紹巴赫溪的入海口，並伴隨一條長達40公里的鹽水徒步道。除了製鹽業，旅遊業自20世紀以來也發展成為當地的主要產業。\r\n\r\n1750年9月20日夜間，哈爾施塔特集鎮遭遇了一場毀滅性的大火。火災起於市集廣場61號的麵包師傅住宅：麵包師傅的妻子想用灰燼中燃燒的餘燼取暖閣樓，卻疏忽了必要的安全措施。周圍的易燃物被引燃，引發了吞噬市集區大片區域的熊熊烈火。所有國有建築，如法院教堂、醫院教堂、鹽場及其附屬建築，以及九戶鹽商的住宅和眾多私人建築，都在這場大火中化為灰燼，並造成四人喪生。總共有35棟房屋被大火燒毀。\r\n\r\n2013年6月18日，洪水氾濫的米爾巴赫河在被堵塞後，衝破了市中心。除了米爾巴赫溪（Mühlbach）的洪水氾濫外，由於湖尾有一座擁有500年曆史的、被列入保護名錄的洩洪堰——施泰格（Steeg）的塞克勞斯（Seeklause），且沒有繞行方案，湖水水位上漲淹沒了一些房屋。\r\n\r\n2018年8月21日，埃赫恩萬德山（Echernwand）上，一根被丟棄的香菸引發了一場森林火災。作為預防措施，鐵索攀岩路線、通往魯道夫塔（Rudolfsturm）的纜車以及鹽礦被迫關閉。在包括奧地利空軍黑鷹直升機在內的多架直升機的協助下，大火被撲滅。\r\n\r\n2019年11月30日星期六，鎮中心西側發生了規模較大的火災。火災起於岸邊的一間木屋，在清晨的黑暗中迅速蔓延，隨後被撲滅。三間相鄰的木屋以及停放在屋內的一輛汽車被燒毀。街道另一側的三棟房屋，其中一些是木結構，外牆和屋頂嚴重受損。市長敦促居民本週末不要前往鎮上，因為清理工作仍在進行中。截至2020年8月，這些房屋已經修繕完畢，但其中一間小屋只剩下殘垣斷壁。市長表示，火災後必須制定發展規劃，但只有在土地所有者就地界達成一致後才能製定。之後，將重建類似的小屋。','https://api.lumoguide.com/storage/uploads/20251108/XV6jeNNBuV4NNIjXNZ0I.png','[\"https://api.lumoguide.com/storage/uploads/20251108/XV6jeNNBuV4NNIjXNZ0I.png\", \"https://api.lumoguide.com/storage/uploads/20251108/kjUuTTqww2rpxI2Wm3z1.png\", \"https://api.lumoguide.com/storage/uploads/20251108/vfCDHuv4gS2cRcGwJAkz.png\", \"https://api.lumoguide.com/storage/uploads/20251108/d7ABNr6fovScK00lIseU.png\", \"https://api.lumoguide.com/storage/images/20260316/7d34558c2ff9caa841304277b509ab07.JPG\", \"https://api.lumoguide.com/storage/uploads/20260321/Aw9USZDzmiMbEXeMNIPa.png\"]',1,NULL,0,0,0,0,0,0,1,'2026-03-21 04:22:41','2026-03-21 04:44:58');


