-- information
INSERT INTO `information` VALUES (1,3,3,2,1,'中国单方面免签“朋友圈”增至47国','中国单方面免签“朋友圈”增至47国','新华社北京6月9日电（记者董雪）6月9日起，中方对沙特、阿曼、科威特、巴林持普通护照人员试行免签政策。至此，适用单方面免签政策来华国家已扩展至47个。\r\n\r\n自2025年6月9日至2026年6月8日，沙特、阿曼、科威特、巴林持普通护照人员来华经商、旅游观光、探亲访友、交流访问、过境不超过30天，可免办签证入境。加上2018年全面互免签证的海合会成员国阿联酋和卡塔尔，中方已实现对海合会国家免签“全覆盖”。\r\n\r\n外交部发言人此前表示，免签“名单”不断变长，彰显了中国持续推进高水平对外开放的坚定决心。中方将持续优化入境政策，不断扩大免签国家范围，让更多外国朋友来中国体验更优质的产品供给、更多元的消费场景和更便利的服务保障，以更大范围的开放、更深层次的合作与各国共享繁荣。','https://api.lumoguide.com/storage/uploads/20251109/5y8MOMJAVh9IKbaOUGWo.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251109\\/5y8MOMJAVh9IKbaOUGWo.png\"]',2,21,1,NULL,0,0,1,1,'2025-11-09 11:46:42','2026-07-06 12:22:10'),(2,3,3,2,2,'图恩湖路段因 “自拍游客” 陷拥堵','图恩湖路段因 “自拍游客” 陷拥堵','2025 年 10 月，瑞士伯尔尼州奥伯兰地区的图恩湖（Thunersee）周边交通问题引发关注 —— 斯皮茨（Spiez）至因特拉肯（Interlaken）的沿湖路段，大量游客为拍摄湖光山色（尤其是尼森山景观）临时减速甚至停车，导致频繁拥堵，当地居民怨声载道。对此，伯尔尼州绿自由党（GLP）州议员罗密欧・阿诺德（Romeo Arnold，37 岁）提出 “自拍停靠区” 与 “游客通行费” 双重方案，试图平衡旅游体验与交通秩序。',NULL,NULL,2,21,1,NULL,0,0,1,1,'2025-11-09 11:46:42','2026-07-04 21:53:34'),(3,3,3,1,7,'克里姆特的肖像画創造拍賣新紀錄','昨天夜裡，克里姆特的肖像畫作在紐約蘇富比拍賣行創造了新紀錄：《Elisabe','昨天夜裡，克里姆特的肖像畫作在紐約蘇富比拍賣行創造了新紀錄：《Elisabeth Lederer肖像》(1914-1916) 這幅畫拍賣行事先估價高達1億3千萬歐元。經過20分鐘的激烈競拍，最終以 2.364 億美元（約合 2.04 億歐元， 不含手續費）的價格，被不知名的一位電話競拍者所得 ( 阿拉伯富豪? 亞洲收藏家? )。這幅畫成為克里姆特作品中售價最高的作品，也是藝術史上繼達芬奇的畫作《救世主》(以 4.503 億美元的價格成交  ) 之後，世界上拍賣價格第二高的作品。\nElisabeth Lederer是維也納猶太企業家August  Lederer 的女兒，August  Lederer曾是羅斯柴爾德家族維也納分支後，維也納第二富有的猶太人。在第三帝國，August  Lederer 一家逃離奧地利， 只有女兒Elisabeth Lederer留在了維也納。她的納粹丈夫與她離婚後，她對外稱自己是克里姆特的女兒，才得以生存下來，1944年在維也納去世。維也納13區，可以參觀克里姆特的別墅畫室。（附該畫局部）\n引用：維也納李力老師的文章','https://api.lumoguide.com/storage/uploads/20251119/0lrViElFwJrOHEM1OW2A.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20251119\\/0lrViElFwJrOHEM1OW2A.png\"]',2,120,1,NULL,0,0,1,1,'2025-11-19 03:09:17','2026-07-04 21:53:33'),(5,3,3,1,7,'2026 Happy new year','你好2026！大家好2026！','你好2026！大家好2026！','https://api.lumoguide.com/storage/uploads/20260102/cfgeBDJkCpG0vG9yPwNr.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20260102\\/cfgeBDJkCpG0vG9yPwNr.png\"]',2,59,1,NULL,0,0,1,1,'2025-12-31 14:33:45','2026-07-04 21:53:32'),(10,40,15,5,10,'路盟Fun積分獎勵','別讓你的專業經驗只停留在記憶裡！在 Lumoguide，每一份內容貢獻、每一次同','別讓你的專業經驗只停留在記憶裡！在 Lumoguide，每一份內容貢獻、每一次同行分享，都是在為你的影響力增值。我們正以最嚴格、最赤誠的標準，回饋每一位先行者的汗水——Fun 積分現正全力發放中！\nFun 商城正緊鑼密鼓升級中，一大波神祕好禮已在路上，即將驚艷亮相。現在就開始累積你的 Fun 實力，等商城大門開啟那一刻，你就是那個能優先兌換心動大獎的贏家。行動，讓你的專業積點成金！','https://api.lumoguide.com/storage/uploads/20260303/RRa5iVxZ4ISAnZfz7IHI.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20260303\\/RRa5iVxZ4ISAnZfz7IHI.png\"]',2,28,1,NULL,0,0,1,1,'2026-03-01 22:48:58','2026-07-05 06:02:39'),(14,40,15,5,10,'贈送三年免費會員的活動！','慶祝Lumo Guide上線，即刻推出三年免費會員的活動！在2026年6月30日之前完成Lu','慶祝Lumo Guide上線，即刻推出三年免費會員的活動！在2026年6月30日之前完成Lumo Guide 旅遊業內人士身份驗證，贈送三年免費會員，旅遊人士所有功能盡情享受！','https://api.lumoguide.com/storage/uploads/20260311/75qSW4kjxrwlUWZHWdsS.png','[\"https:\\/\\/api.lumoguide.com\\/storage\\/uploads\\/20260311\\/75qSW4kjxrwlUWZHWdsS.png\"]',1,11,1,NULL,0,0,1,1,'2026-03-11 02:13:05','2026-07-15 20:08:15'),(16,3,3,1,7,'安全提醒','各位大导请注意：\n\n2026年3月18号下午铁力士因大风天气发生严重事故，已造成一名游客不幸身亡。请大家务必高度重视高山项目的安全风险。\n\n阿尔卑斯山区天气变化极快，尤其是风力因素，对缆车运行影响较大。为确保团队安全与行程稳定，建议在推荐阿尔卑斯山自费项目时优先考虑：\n\n✅ 优先推荐齿轨火车类项目（安全性更高、稳定性更强）\n如：瑞吉山、少女峰铁路等\n➡ 受天气影响相对较小\n➡ 运行稳定，取消概率低','各位大导请注意：\n\n2026年3月18号下午铁力士因大风天气发生严重事故，已造成一名游客不幸身亡。请大家务必高度重视高山项目的安全风险。\n\n阿尔卑斯山区天气变化极快，尤其是风力因素，对缆车运行影响较大。为确保团队安全与行程稳定，建议在推荐阿尔卑斯山自费项目时优先考虑：\n\n✅ 优先推荐齿轨火车类项目（安全性更高、稳定性更强）\n如：瑞吉山、少女峰铁路等\n➡ 受天气影响相对较小\n➡ 运行稳定，取消概率低\n➡ 客人体验更可控',NULL,NULL,1,0,1,NULL,0,0,1,1,'2026-03-18 12:03:20','2026-03-18 12:35:49'),(17,50,20,1,3,'禁止带队进入St. Peter墓地','St. Peter的负责人最近再三强调不允许导游和领队带团进入 Friedhof，更不允许入园讲解。','St. Peter的负责人最近再三强调不允许导游和领队带团进入 Friedhof，更不允许入园讲解。',NULL,NULL,1,0,1,NULL,0,0,0,1,'2026-04-08 23:57:38','2026-04-08 23:57:38'),(18,50,20,1,7,'莫扎特出生地博物馆闭馆信息','由于施工原因，莫扎特出生地博物馆将于2026年5月21日和5月22日全天关闭。','由于施工原因，莫扎特出生地博物馆将于2026年5月21日和5月22日全天关闭。',NULL,NULL,1,0,1,NULL,0,0,0,1,'2026-04-09 00:34:51','2026-04-09 00:34:51');


